vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-195948369&id=456239136&hash=ea0f44275d52ff3f&hd=2\" width=\"853\" height=\"480\"></iframe>"},{"hosting":"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-195948369&id=456239140&hash=f7f6b3348748f91d&hd=2\" width=\"853\" height=\"480\"></iframe>"},{"hosting":"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-152985925&id=456240646&hash=23ad914f4cd52bc0&hd=2\" width=\"853\" height=\"480\"></iframe>"}]', NULL, '{"to": "18:00:00", "from": "12:00:00"}', '{"to": "18:00:00", "from": "12:00:00"}', '{"to": "18:00:00", "from": "12:00:00"}', '{"to": "18:00:00", "from": "12:00:00"}', '{"to": "18:00:00", "from": "12:00:00"}', '{"to": "18:00:00", "from": "12:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 77911, '[{"url":"https://www.culture.ru/institutes/90793/aristovskii-klub","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/101180pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=4116b9c8-86de-4036-b51c-67649d2309d3&shareType=venue","serviceName":"ФанТам"}]', 77911, NULL, NULL, NULL, '2023-03-20 15:39:36+03', '2025-07-10 12:39:24+03', '0101000020E61000003EEDF0D764334740B5C35F9335624E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Кадуйский центр культурного развития', 'Кадуйский район', 'Europe/Moscow', 'ул Строителей,д 2', NULL, 'обл Вологодская,р-н Кадуйский,рп Кадуй,ул Строителей,д 2', '{"type": "Point", "coordinates": [37.104571, 59.208443]}', '<p>Дом культуры был построен в 1984 году и сразу стал центром притяжения для кадуйчан. В его стенах организованы занятия для людей разных возрастов и интересов. Здесь проводят свободное время, реализуя свои таланты и способности, дети и взрослые, студенты и пенсионеры.</p><p> В Доме культуры работает более 30 клубных формирований, из них 15 самодеятельного народного творчества. 6 коллективов имеют звание народного самодеятельного коллектива, а танцевальный коллектив «Кнопочки» – звание образцового художественного коллектива. </p><p>Здесь есть эстрадная студия, театр, хор русской песни. Молодежь с удовольствием занимается в молодежном объединении «Ассоциация лидеров», участвует в волонтерской и экологической деятельности. Вокальный ансамбль Cantabile имеет множество наград международных конкурсов классического хорового вокала.</p><p>В 2020 году в рамках проекта Фонда кино и Министерства культуры РФ на втором этаже Кадуйского дома культуры открылся кинозал на 60 мест. Теперь кадуйчане могут посмотреть премьеры кинофильмов, не выезжая для этого в другие города. </p><p> </p>', 'https://mbuk-kdk.ru', 'calturehome@mail.ru', '[{"value": "78174252431", "comment": "Художественный руководитель"}]', '{"url": "https://all.culture.ru/uploads/0d9c3a39ac37226c18002d9dc8ab74d4.jpg", "title": "14082020x33f89b77.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУ «Кадуйский ЦКР»', 'Вологодская область', 'Europe/Moscow', 'ул Строителей,д 2', NULL, 'обл Вологодская,рп Кадуй,ул Строителей,д 2', NULL, 3510010837, 'mincult', 'Вологодская область', 'Europe/Moscow', '[{"network":"ok","name":"Елена Белькович (Соболева)","networkId":"437912980","updateDate":"2025-06-10T07:54:02Z","createDate":"2025-06-10T07:54:02Z","accountId":49941,"postingGroupId":48056},{"network":"ok","name":"Культура. Кадуй","networkId":"61103236120724","updateDate":"2024-02-16T11:35:59Z","createDate":"2024-02-16T11:35:59Z","accountId":49941,"postingGroupId":44748}]', 36609, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 753, "name": "Кинозал", "sysName": "kinozal"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "23:00:00", "from": "09:00:00"}', '{"to": "23:00:00", "from": "09:00:00"}', '{"to": "23:00:00", "from": "09:00:00"}', '{"to": "23:00:00", "from": "09:00:00"}', '{"to": "23:00:00", "from": "09:00:00"}', '{"to": "23:00:00", "from": "09:00:00"}', '{"to": "23:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 83291, '[{"url":"https://www.culture.ru/institutes/96239/kaduiskii-centr-kulturnogo-razvitiya","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/kaduy/dvorcy-kultury-i-kluby/110796pl","serviceName":"Афиша7"}]', 83291, NULL, NULL, NULL, '2024-02-21 23:18:38+03', '2025-09-01 16:53:45+03', '0101000020E6100000158E2095628D4240420A9E42AE9A4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Центр культуры г. Харовска', 'Харовский район', 'Europe/Moscow', 'ул Энергетиков,д 11', NULL, 'обл Вологодская,р-н Харовский,г Харовск,ул Энергетиков,д 11', '{"type": "Point", "coordinates": [40.21833, 59.951303]}', '<p>Учреждение было введено в эксплуатацию в 1967 году. Зрительный зал рассчитан на 300 посадочных мест. Также в здании есть танцевальный зал, зал для занятий хореографией, игровые комнаты. Благодаря победе в конкурсе Федерального фонда социальной и экономической поддержки кинематографии кинозал обрел новую жизнь накануне 50-летия Дома культуры. </p><p>Ежегодно более 300 культурно-досуговых мероприятий посещает свыше 50 000 человек. Ведут работу 40 клубных формирований, в которых занимаются местные жители в возрасте от 4 до 70 лет. Четыре коллектива имеют звание «народный».<span> Творческие к</span>оллективы<span> </span>являются активными участниками федеральных, региональных, муниципальных, городских фестивалей, конкурсов и мероприятий. </p>', 'https://gdkmirx.ru', 'gdk.mirharovsk@haradm.ru', '[{"value": "78173221731", "comment": "Т. Н. Скворцова"}]', '{"url": "https://all.culture.ru/uploads/d56a52e7877422180658adda9dc3c80a.jpg", "title": "IMG_20230810_085135.jpg"}', '[{"url": "https://all.culture.ru/uploads/45a3e02af2616d3ba2c0aa7e1b183e4d.jpg", "title": "mdkALQp2ZKw.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МБУК «ГДК «МИР»', 'Харовский район', 'Europe/Moscow', 'ул Энергетиков,д 11', NULL, 'обл Вологодская,р-н Харовский,г Харовск,ул Энергетиков,д 11', NULL, 3521006279, 'mincult', 'Харовский район', 'Europe/Moscow', NULL, 20589, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 753, "name": "Кинозал", "sysName": "kinozal"}, {"id": 122, "name": "Искусство", "sysName": "iskusstvo"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 61727, '[{"url":"https://www.culture.ru/institutes/62434/centr-kultury-g-kharovska","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/harovsk/dvorcy-kultury-i-kluby/88037pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=f36af10c-61d4-466a-b880-adf5324a0b16&shareType=venue","serviceName":"ФанТам"}]', 61727, NULL, NULL, NULL, '2022-02-11 10:16:47+03', '2025-09-01 10:46:05+03', '0101000020E61000002BDEC83CF21B444019CBF44BC4F94D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Центральный дом культуры с. Кичменгский Городок', 'Кичменгско-Городецкий район', 'Europe/Moscow', 'ул Центральная,д 8', NULL, 'обл Вологодская,р-н Кичменгско-Городецкий,с Кичменгский Городок,ул Центральная,д 8', '{"type": "Point", "coordinates": [45.80272614955902, 59.99222069044922]}', '<p>Дом культуры начал свою работу в 1989 году. Он является центром культуры Кичменгско-Городецкого района, здесь проходят все основные районные фестивали, конкурсы, концерты, театрализованные постановки, встречи, семинары.<br /><br />На базе ДК занимается более 20 творческих коллективов: вокальных, танцевальных, театральных и инструментальных. Четыре из них имеют звание «Народный самодеятельный коллектив».<br /><br />В 2017 году ДК получил грант в размере пяти миллионов рублей от Федерального фонда социальной и экономической поддержки отечественной кинематографии для оборудования кинозала.<br /><br />Сегодня кинозал имеет все необходимое для показа фильмов на высоком профессиональном уровне. С 4 августа 2018 года здесь регулярно проходят показы фильмов и мультфильмов в двух форматах – 2D и 3D. С 31 января 2019 года учреждение работает с фирмой «Премьер-зал» по поставке кинофильмов.<br /><br />16 февраля 2023 года Районный дом культуры Кичменгско-Городецкого муниципального района Вологодской области переименован в Центральный дом культуры Кичменгско-Городецкого муниципального округа Вологодской области на основании приказа Управления культуры «О внесении изменений в уставные документы» № 112 от 30.12.2022.</p>', 'https://rdk-kg.vlg.muzkult.ru/event/s/afisha', 'rdkgorodok@mail.ru', '[{"value": "78174021120", "comment": "Копосова Татьяна Николаевна"}]', '{"url": "https://all.culture.ru/uploads/5ddb8e87578d2c42fa7d52409e8e7670.jpg", "title": "Рисунок1 (1).jpg"}', '[{"url": "https://all.culture.ru/uploads/d17a26a29207fdbc747a4c387b76ed5a.jpeg", "title": "5LV8N12D7Z4.jpg"}, {"url": "https://all.culture.ru/uploads/67b0106af229903ae9aaf097e36cf03e.jpeg", "title": "KE4dW4vt8Tw.jpg"}, {"url": "https://all.culture.ru/uploads/5125547b61bf04820fa423a00c0141de.jpeg", "title": "MkSmAFan7hk.jpg"}, {"url": "https://all.culture.ru/uploads/c610c1104831dfabbc619c26bbf02f77.jpeg", "title": "MZo2cgTg5Dc.jpg"}, {"url": "https://all.culture.ru/uploads/a83d493d1cb7e2a677b8e7dffb72e9ea.jpeg", "title": "nqVxyZ-A1n4.jpg"}, {"url": "https://all.culture.ru/uploads/8eecbd90ae2bd5c563b8ac22d660166c.jpeg", "title": "oyQn4jjcobM.jpg"}, {"url": "https://all.culture.ru/uploads/c8e194191ac8e87624b271d8b7663b87.jpeg", "title": "YCMaMrASOs4.jpg"}]', NULL, 'Дворцы культуры и клубы', 'БУК «Районный дом культуры»', 'Кичменгско-Городецкий район', 'Europe/Moscow', 'ул Центральная', NULL, 'обл Вологодская,р-н Кичменгско-Городецкий,с Кичменгский Городок,ул Центральная', NULL, 3512005007, 'mincult', 'Кичменгско-Городецкий район', 'Europe/Moscow', NULL, 20268, '[{"id": 753, "name": "Кинозал", "sysName": "kinozal"}, {"id": 122, "name": "Искусство", "sysName": "iskusstvo"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "21:00:00", "from": "08:30:00"}', '{"to": "21:00:00", "from": "08:30:00"}', '{"to": "21:00:00", "from": "08:30:00"}', '{"to": "21:00:00", "from": "08:30:00"}', '{"to": "21:00:00", "from": "08:30:00"}', '{"to": "20:00:00", "from": "12:00:00"}', '{"to": "20:00:00", "from": "12:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 40035, '[{"url":"https://www.culture.ru/institutes/40814/centralnyi-dom-kultury-s-kichmengskii-gorodok","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/kichmengskiy-gorodok/dvorcy-kultury-i-kluby/22003pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=4cf10653-4a36-4be4-bf37-ead8b0fe43ec&shareType=venue","serviceName":"ФанТам"}]', 40035, NULL, NULL, NULL, '2019-10-04 11:14:38+03', '2025-08-29 17:51:44+03', '0101000020E6100000000000BBBFE646406DF26B1601FF4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Культурный центр «Сухонский» г. Сокола', 'Сокольский район', 'Europe/Moscow', 'ул Советская,д 115', NULL, 'обл Вологодская,р-н Сокольский,г Сокол,ул Советская,д 115', '{"type": "Point", "coordinates": [40.087841, 59.474596]}', '<p> Культурный центр «Сухонский» является ведущим учреждением культуры, где проходят значимые для города и Сокольского округа мероприятия: фестивали, конкурсы, концерты, игровые программы и др. Центр организует постановку театральных и оперных представлений, проведение концертов и прочих сценических выступлений, мероприятий информационного, культурного и общественного характера. На его базе работают 37 клубных формирований, из них 20 формирований для детей до 14 лет и 6 формирований для молодежи до 24 лет. </p><p> Культурный центр тесно взаимодействует с администрацией Сокольского муниципального округа, учебными заведениями, предприятиями и общественными организациями города и округа. Тесное сотрудничество, взаимодействие и партнерство поддерживается с дворцами культуры и клубами сельских поселений Сокольского округа. </p>', 'http://kulturnycentr.ru', 'cult-sokol@yandex.ru', '[{"value": "78173332739", "comment": "методический кабинет"}]', '{"url": "https://all.culture.ru/uploads/025a2a17e8ed501fcf5c9cf9f54bd669.jpg", "title": "2167b3b4be48b2f7626427b0a62e38de.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК СМО Культурный центр «Сухонский»', 'Сокольский район', 'Europe/Moscow', 'ул Советская,д 115', NULL, 'обл Вологодская,р-н Сокольский,г Сокол,ул Советская,д 115', NULL, 3527011758, 'mincult', 'Сокольский район', 'Europe/Moscow', '[{"network":"vk","name":"БУК СМО КЦ \"Сухонский\"","networkId":"16111380","updateDate":"2023-03-29T09:51:40Z","createDate":"2023-03-29T09:51:40Z","accountId":22652,"postingGroupId":41301}]', 12852, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "19:00:00", "from": "08:00:00"}', '{"to": "19:00:00", "from": "08:00:00"}', '{"to": "19:00:00", "from": "08:00:00"}', '{"to": "19:00:00", "from": "08:00:00"}', '{"to": "19:00:00", "from": "08:00:00"}', '{"to": "19:00:00", "from": "08:00:00"}', '{"to": "19:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 39081, '[{"url":"https://www.culture.ru/institutes/40121/kulturnyi-centr-sukhonskii-g-sokola","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/sokol/dvorcy-kultury-i-kluby/21599pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=1187f24c-d0b1-4d61-8a0b-6a1bb3ce9c33&shareType=venue","serviceName":"ФанТам"}]', 39081, NULL, NULL, NULL, '2019-05-23 11:47:29+03', '2025-08-29 17:22:46+03', '0101000020E6100000BC1FB75F3E0B4440FD67CD8FBFBC4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Центр культурного развития г. Красавино', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 152', NULL, 'обл Вологодская,р-н Великоустюгский,г Красавино,пр-кт Советский,д 152', '{"type": "Point", "coordinates": [46.48133, 60.960158]}', '<p>Дом культуры и спорта г. Красавино основан в 1929 году. В учреждении с 1991 года работают несколько центров:</p><ol><li>Информационно-издательский центр занимается выпуском еженедельного издания «Красавинский вестник», оказывает полиграфические услуги населению, а также обеспечивает рекламной и полиграфической продукцией мероприятия Дома культуры.</li><li>Центр народной традиционной культуры «Русская изба» проводит экскурсии, мастер-классы, программы для детей, а также тематические программы для взрослых. Гости погружаются в атмосферу традиционного уклада жизни, играют в народные игры, участвуют в обрядовых праздниках.</li><li>Просветительский центр «Светоч» занимается оформлением и проведением выставок местных умельцев по изобразительному и декоративно-прикладному творчеству, проведением интерактивных программ, мастер-классов. В центре работает выставочная площадка «Красавино. Нити эпох», «Кабинет купца Грибанова», «Путешествие по Вологодскому краю». Ежегодно издаются литературные сборники по истории города.</li><li>Художественно-концертный отдел ежегодно проводит городские, областные и межрегиональные фестивали и конкурсы, выставки и презентации, праздничные дискотеки и игры КВН, спортивные соревнования и концерты профессиональных и самодеятельных артистов. Кружки, секции, студии ежедневно принимают горожан: от самых маленьких посетителей дошкольного возраста до пожилых людей, ветеранов.</li></ol><p>Для жителей города работают:</p><ul><li>народный самодеятельный коллектив хореографическая студия «Улыбка»;</li><li>народный самодеятельный коллектив цирковая студия «Романтики»;</li><li>образцовый коллектив студия прикладного творчества «Кудесница»;</li><li>секция УШУ-Саньда;</li><li>клуб «Здоровье»;</li><li>вокальный ансамбль «Надежда»;</li><li>студия творческого развития «Мир волшебства»;</li><li>народный самодеятельный коллектив театр русского костюма «Берегиня»;</li><li>студия «Барби-Стиль»;</li><li>студия восточного танца «Жемчужина»;</li><li>клуб «Печки-лавочки»;</li><li>развивающий центр «РОСТ''ОК»;</li><li>развивающий центр «РОСТ''ОК. Подготовка к школе»;</li><li>танцы для взрослых;</li><li>танцы для старшего поколения Maxi;</li><li>программа «Фитнес-mix»;</li><li>клуб «Красавино. Нити эпох».</li></ul>', 'http://www.dciskrasavino.ru', 'dciskrasavino@mail.ru', '[{"value": "78173841933", "comment": "директор, канцелярия"}, {"value": "78173841185", "comment": "касса, вахта"}]', '{"url": "https://all.culture.ru/uploads/d40ed51a4738717869860ba2c69210cd.jpg", "title": "9mae5e5VGf0.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Центр культурного развития г. Красавино»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 152', NULL, 'обл Вологодская,р-н Великоустюгский,г Красавино,пр-кт Советский,д 152', NULL, 3526008640, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"Дом культуры и спорта г.Красавино","networkId":"33505837","updateDate":"2018-09-03T11:42:38Z","createDate":"2018-09-03T11:42:38Z","accountId":22303,"postingGroupId":19717},{"network":"vk","name":"Народная хореографическая студия \"Улыбка\"(г.Крас","networkId":"5759262","updateDate":"2018-09-03T11:43:10Z","createDate":"2018-09-03T11:43:10Z","accountId":22303,"postingGroupId":19718},{"network":"vk","name":"Просветительский центр \"Светоч\" ДКиС г.Красавино","networkId":"115057099","updateDate":"2018-09-03T11:44:09Z","createDate":"2018-09-03T11:44:09Z","accountId":22303,"postingGroupId":19720}]', 20579, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "21:00:00", "from": "07:30:00"}', '{"to": "21:00:00", "from": "07:30:00"}', '{"to": "21:00:00", "from": "07:30:00"}', '{"to": "21:00:00", "from": "07:30:00"}', '{"to": "21:00:00", "from": "07:30:00"}', '{"to": "16:00:00", "from": "07:30:00"}', '{"to": "16:00:00", "from": "07:30:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35859, '[{"url":"https://www.culture.ru/institutes/36480/centr-kulturnogo-razvitiya-g-krasavino","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/19588pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=a64d6fa3-d6d7-4a22-8512-f7e267d3331c&shareType=venue","serviceName":"ФанТам"}]', 35859, NULL, NULL, NULL, '2018-08-31 11:58:08+03', '2025-08-27 11:05:18+03', '0101000020E6100000B64AB0389C3D4740137F1475E67A4E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Дворец металлургов г. Череповца', 'Череповец', 'Europe/Moscow', 'ул Сталеваров,д 41', NULL, 'обл Вологодская,г Череповец,ул Сталеваров,д 41', '{"type": "Point", "coordinates": [37.901512, 59.120432]}', '<p><span>В июле 1993 года на берегу Шексны среди зелени и фонтанов распахнул свои двери Дворец металлургов. И на протяжении двух десятков лет он является достопримечательностью Череповца, радует жителей и гостей города не только строгостью архитектурных линий и своим внутренним убранством, но и профессиональным коллективом единомышленников. </span></p><p><span>Дворец традиционно является организатором крупнейших городских мероприятий. </span>Десятки тысяч горожан и гостей города ежегодно посещают учреждение, получая возможность приобщиться к высокому искусству, увидеть лучшие профессиональные и самодеятельные коллективы.</p><p><span>На базе Дворца металлургов работает семь профессиональных творческих коллективов: </span></p><ol><li><span>Молодежный цирк «Супер-Скок».</span></li><li><span>Танцевальный клуб «Мальвина».</span></li><li><span>Шоу-балет «Магия».</span></li><li><span>Концертный ансамбль под руководством заслуженного работника культуры РФ Хинского Г. Д. </span></li><li><span>Театр мод.</span></li><li><span>Студия эстрадного вокала «Арт-мажор».</span></li><li><span>Студия современной хореографии «Ибис».</span></li><li><span>Хореографический коллектив «Горошинки». </span></li></ol><p><span>На протяжении пятидесяти лет радует своим творчеством зрителей еще один уникальный заслуженный коллектив народного творчества – Хор ветеранов войны и труда имени В. Д. Чибисова. </span></p><p><span>Дворец металлургов – крупнейшее учреждение культуры Вологодской области, это великолепное место для проведения концертов, корпоративных мероприятий, юбилейных празднеств, конкурсов и фестивалей, торжественных приемов и собраний, деловых встреч высокого уровня. </span></p>', 'http://dvorecmet.ru', 'dm@dvorecmet.ru', '[{"value": "78202570195", "comment": "вахта"}, {"value": "78202572385", "comment": "кассы"}]', '{"url": "https://all.culture.ru/uploads/7bbc687a4a9871375c7a1c024b72a09c.jpg", "title": "3D9VSswBIso[1].jpg"}', '[{"url": "https://all.culture.ru/uploads/3f19defd4a92ee640b172396e13447df.jpg", "title": "qzbrnIixHrE[1].jpg"}, {"url": "https://all.culture.ru/uploads/cfef4907112f2d401a2ccc9da6acc766.jpg", "title": "75H2QLwaAec[1].jpg"}, {"url": "https://all.culture.ru/uploads/ecefa86ca89bee7ea3d95450c7e86d80.jpg", "title": "CPAEJPjLuFc[1].jpg"}, {"url": "https://all.culture.ru/uploads/1b57ab18a467bf8f439589364cac44b1.jpg", "title": "ACI_eDNvSCM[1].jpg"}, {"url": "https://all.culture.ru/uploads/7186634afa62dc3515c1cd938e80fada.jpg", "title": "9hskr3W_gg0.jpg"}, {"url": "https://all.culture.ru/uploads/79e82c89fc5bf03850d19f37da931465.jpg", "title": "DSCN0229.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МАУК «Дворец металлургов»', 'Череповец', 'Europe/Moscow', 'ул Сталеваров,д 41', NULL, 'обл Вологодская,г Череповец,ул Сталеваров,д 41', NULL, 3528086805, 'mincult', 'Череповец', 'Europe/Moscow', NULL, 20174, '[{"id": 273, "name": "Отдых и развлечения", "sysName": "otdyh-i-razvlecheniya"}, {"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 34417, '[{"url":"https://afisha7.ru/cherepovec/dvorcy-kultury-i-kluby/18819pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/35683/dvorec-metallurgov-g-cherepovca","serviceName":"Культура.рф"},{"url":"https://spbcult.ru/places/dvorets-metallurgov-g-cherepovtsa/","serviceName":"Портал «Культура Петербурга»"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=f1b4b93e-1036-427f-924d-3aef21fc653e&shareType=venue","serviceName":"ФанТам"}]', 34417, NULL, NULL, NULL, '2018-04-11 09:52:10+03', '2025-08-29 16:33:48+03', '0101000020E6100000CC79C6BE64F3424029B2D6506A8F4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Культурно-досуговый центр г. Грязовца', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', '{"type": "Point", "coordinates": [40.245297, 58.880677]}', '<p>Культурно-досуговый центр – это место, где можно культурно провести время, разнообразить досуг и получить приятные эмоции.</p><p>КДЦ был построен в 1974 году. Возглавляла культурную деятельность грязовчан на тот момент Малышева Антонина Константиновна.</p><p>В настоящее время исполняющим обязанности директора КДЦ является Н. А. Водополова.</p><p>На базе центра осуществляют свою деятельность 35 клубных формирований, в которых получают услуги 658 человек.</p><p> </p><p>Ежегодно проводятся социально значимые праздники: «Рождественские звезды», Масленица, «Праздник труда», «Звездная дорожка», «Битва талантов», День Победы, День защиты детей, «Праздник липы», День пожилого человека, а также новогодние праздники.</p><p> </p><p>28 января 2018 года в КДЦ состоялось торжественное открытие кинотеатра при поддержке губернатора Вологодской области, администрации Грязовецкого муниципального района, а также Федерального фонда поддержки отечественного кино.</p><p>Кинотеатр КДЦ является участником всех региональных и международных кинофестивалей, а также различных акций.</p>', 'https://kdc.vlg.muzkult.ru', 'kultdosugcentr@mail.ru', '[{"value": "78175521031", "comment": "специалисты"}, {"value": "78175522632", "comment": "директор, экономический отдел"}]', '{"url": "https://all.culture.ru/uploads/0a95ea9e7bc31a359848c7cb87a0d8e1.jpeg", "title": "Yndn3yqDJXw.jpg"}', '[{"url": "https://all.culture.ru/uploads/fb8f6ba255db445862530905a5111310.jpeg", "title": "Djm6H-bKn48.jpg"}, {"url": "https://all.culture.ru/uploads/08b691c8e7eb6b570bb59e63ee3e82c2.jpeg", "title": "8f4Zj6MpKA4.jpg"}, {"url": "https://all.culture.ru/uploads/a50ee0c3a5b8f304ffa560fc2b48a03a.jpeg", "title": "BUmeUIXdIXs.jpg"}, {"url": "https://all.culture.ru/uploads/b7e98f274e9d3b6d2fd2cdbf43cf79e5.jpeg", "title": "XX5s4DT3zaA.jpg"}, {"url": "https://all.culture.ru/uploads/7575b6cf9eb3b75113bbfa3d8fc01248.jpeg", "title": "QKdxTTKpZJA.jpg"}, {"url": "https://all.culture.ru/uploads/9290373162f685399729b1ab1e7534a9.jpeg", "title": "AvLdGIh71B0.jpg"}]', NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 753, "name": "Кинозал", "sysName": "kinozal"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 27998, '[{"url":"https://www.culture.ru/institutes/30360/kulturno-dosugovyi-centr-g-gryazovca","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/14940pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=463f92b9-4f47-4441-be9b-cf86a6be50f7&shareType=venue","serviceName":"ФанТам"}]', 27998, NULL, NULL, NULL, '2017-01-11 16:12:45+03', '2025-09-01 09:41:22+03', '0101000020E6100000496760E4651F444071AB2006BA704D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Никольский районный дом культуры', 'Никольский район', 'Europe/Moscow', 'ул Советская,д 91', 'от областного центра г. Вологды автобусом, маршрутным такси – 420 км; от ж/д станции Шарья автобусом – 160 км; от г. Великого Устюга автобусом – 160 км', 'обл Вологодская,р-н Никольский,г Никольск,ул Советская,д 91', '{"type": "Point", "coordinates": [45.458095000000014, 59.530763]}', '<p>Районный дом культуры открылся в 2007 году. Основная деятельность Дома культуры направлена на предоставление населению культурно-досуговых услуг. </p><p>В настоящее время в учреждении работают 47 клубных формирований – это клубы по интересам, коллективы художественной самодеятельности, кружки прикладного творчества. В них участвует 625 человек. Коллектив РДК работоспособный и творческий, сплоченный и дружный. Сотрудники используют инновационные формы работы: квесты, квизы, шоу-программы и др. Особое внимание уделяется работе с детьми в каникулярное время. Используется современное световое и звуковое оборудование.</p>', 'http://культура-никольск.рф', 'imckt@mail.ru', '[{"value": "78175422257", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/9c8bf9b41fff28641321091be6b39086.jpg", "title": "100722-1068719324.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Районный Дом культуры»', 'Никольский район', 'Europe/Moscow', 'ул Советская,д 91', NULL, 'обл Вологодская,р-н Никольский,г Никольск,ул Советская,д 91', NULL, 3514007225, 'mincult', 'Никольский район', 'Europe/Moscow', NULL, 17278, '[{"id": 350, "name": "Народная культура", "sysName": "narodnaya-kultura"}, {"id": 273, "name": "Отдых и развлечения", "sysName": "otdyh-i-razvlecheniya"}, {"id": 753, "name": "Кинозал", "sysName": "kinozal"}, {"id": 206, "name": "Народное творчество", "sysName": "narodnoe-tvorchestvo"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 26717, '[{"url":"https://muzaticket.ru/places/3134/nikolskii-raionnyi-dom-kultury","serviceName":"2do2go (Культрег)"},{"url":"https://www.culture.ru/institutes/30642/nikolskii-raionnyi-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/nikolsk-35/dvorcy-kultury-i-kluby/14213pl","serviceName":"Афиша7"},{"url":"https://2do2go.ru/places/3134/nikolskii-raionnyi-dom-kultury","serviceName":"2do2go (Культрег)"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=9ec6d8da-81c0-45d9-8fbc-4b2909fab925&shareType=venue","serviceName":"ФанТам"}]', 26717, NULL, NULL, NULL, '2016-11-14 10:11:37+03', '2025-08-28 17:01:56+03', '0101000020E610000008BB61DBA2BA4640A376BF0AF0C34D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Центр развития культуры «Тотьма»', 'Тотемский район', 'Europe/Moscow', 'ул Вологодская,д 11', NULL, 'обл Вологодская,р-н Тотемский,д Варницы,ул Вологодская,д 11', '{"type": "Point", "coordinates": [42.755945, 59.988041]}', '<p>Центр развития культуры «Тотьма» – это центр культурной жизни тотьмичей, источник приятных эмоций и хорошего настроения. </p><p>В июле 2018 года ЦРК распахнул свои двери для работников и посетителей. В своей деятельности учреждение опирается на следующие основные направления: патриотическое воспитание граждан, сохранение воспитательного потенциала семьи, развитие спорта, а также сохранение и возрождение народных традиций, обрядов, праздников и обычаев. Здесь ведется работа по организации досуга для всех возрастных категорий населения.</p><p> Творческие коллективы ЦРК «Тотьма» принимают активное участие в организации и проведении всех мероприятий округа. Клубы по интересам посещают желающие научиться петь, танцевать, играть на гитаре, а также любители театрального искусства и декоративно-прикладного творчества. И создает все это дружная работоспособная команда профессионалов, людей увлеченных и любящих свою профессию. <br /></p>', NULL, NULL, NULL, '{"url": "https://all.culture.ru/uploads/1257879faa26cb268b7dd3d43a1bfa76.jpg", "title": "jQQTf-c2KQQ.jpg"}', '[{"url": "https://all.culture.ru/uploads/cdf9fa8cfca0d60d8f9404bd8d7aea8a.jpg", "title": "JL3GJkvKIdI.jpg"}, {"url": "https://all.culture.ru/uploads/bc3fef95f320fd6e9c7d794e52783922.jpg", "title": "CE3oWklt4y0.jpg"}]', NULL, 'Дворцы культуры и клубы', 'Муниципальное бюджетное учреждение культуры «Центр развития культуры «Тотьма»', 'Тотемский район', 'Europe/Moscow', 'Вологодская,11', NULL, 'обл Вологодская,р-н Тотемский,д Варницы,Вологодская,11', NULL, 3518003616, 'mincult', 'Тотемский район', 'Europe/Moscow', NULL, 25908, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 78222, '[{"url":"https://www.culture.ru/institutes/91114/centr-razvitiya-kultury-totma","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/totma/dvorcy-kultury-i-kluby/98859pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=8dd8a1cb-a22d-4819-a270-6cd74a52072d&shareType=venue","serviceName":"ФанТам"}]', 78222, NULL, NULL, NULL, '2023-03-27 09:59:09+03', '2025-09-11 17:19:55+03', '0101000020E6100000904946CEC2604540B70DA32078FE4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Архангельский дом культуры', 'Сокольский район', 'Europe/Moscow', 'тер Сельскохозяйственная,д 40', 'авт. № 2, авт. «Сокол – с. Архангельское»', 'обл Вологодская,р-н Сокольский,с Архангельское,тер Сельскохозяйственная,д 40', '{"type": "Point", "coordinates": [39.953641, 59.540595]}', '<p>В Доме культуры проходят мероприятия различного формата для разных возрастных категорий: игровые, спортивные, интерактивные программы, вечера отдыха, концерты творческих коллективов, фестивали и конкурсы, выставки творческих работ, творческие встречи, театрализованные программы, экскурсии и др. Заведующая филиалом – Вера Юрьевна Денисова. </p><p>На базе Архангельского дома культуры работают творческие коллективы, кружки и секции: бильярд-клуб, подростковый клуб «Перспектива», клуб здоровья «Грация», клуб рукоделия, клуб ветеранов, клуб для инвалидов «Можем все», клуб «Настольный теннис», клуб семейный, танцевальный коллектив «Ритм», экскурсионный клуб «На землю древнюю и величавую».</p>', 'http://kulturnycentr.ru/filialy', 'cult-sokol@yandex.ru', '[{"value": "79215303413", "comment": ""}, {"value": "79005575547", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/d1b23b77ee41229fea6cecfae58d9954.JPG", "title": "DSCN7178.JPG"}', '[{"url": "https://all.culture.ru/uploads/ac411aea60a4d18a3a9b2fd5eca1d691.jpeg", "title": "HH9Vnm1jorw.jpg"}, {"url": "https://all.culture.ru/uploads/5c455c01f5a2852385872465e1d53063.jpeg", "title": "MxUUeS3feZI.jpg"}, {"url": "https://all.culture.ru/uploads/9f94d4e6ab17e237a16fc0b0fec03911.jpeg", "title": "uUGge7JpkLM.jpg"}, {"url": "https://all.culture.ru/uploads/3a6e4b50761b2101136a67fadb7308d7.jpeg", "title": "ViPYXN_3VwY.jpg"}, {"url": "https://all.culture.ru/uploads/65755147a717674840c1dc41b03aa499.jpeg", "title": "WSJbrifxN8E.jpg"}, {"url": "https://all.culture.ru/uploads/6296a48538a01526855825e3b42a1247.jpeg", "title": "tO7RGPiUK34.jpg"}]', NULL, 'Дворцы культуры и клубы', 'БУК СМО Культурный центр «Сухонский»', 'Сокольский район', 'Europe/Moscow', 'ул Советская,д 115', NULL, 'обл Вологодская,р-н Сокольский,г Сокол,ул Советская,д 115', NULL, 3527011758, 'mincult', 'Сокольский район', 'Europe/Moscow', '[{"network":"vk","name":"БУК СМО КЦ \"Сухонский\"","networkId":"16111380","updateDate":"2023-03-29T09:51:40Z","createDate":"2023-03-29T09:51:40Z","accountId":22652,"postingGroupId":41301}]', 12852, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 26, "name": "Современное искусство", "sysName": "sovremennoe-iskusstvo"}, {"id": 122, "name": "Искусство", "sysName": "iskusstvo"}, {"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 25, "name": "Классическое искусство", "sysName": "klassicheskoe-iskusstvo"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 61497, '[{"url":"https://www.culture.ru/institutes/62116/arkhangelskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/sokol/dvorcy-kultury-i-kluby/65796pl","serviceName":"Афиша7"}]', 61497, NULL, NULL, NULL, '2022-02-10 08:55:45+03', '2025-09-04 10:19:43+03', '0101000020E6100000F78F85E810FA4340C9B08A3732C54D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Вожегодский центр культурного развития', 'Вожегодский район', 'Europe/Moscow', 'ул Садовая,д 10', NULL, 'обл Вологодская,р-н Вожегодский,рп Вожега,ул Садовая,д 10', '{"type": "Point", "coordinates": [40.208484, 60.474604]}', '<p>Вожегодский центр культурного развития был открыт 2 августа 2008 года на межрегиональной ярмарке «Российские губернаторы в глубинке». Для вожегодцев созданы все условия для комфортного проведения досуга: уютный зрительный зал на 350 мест, просторные классы для кружковых занятий, оборудованный новой светозвуковой аппаратурой танцевальный зал для проведения дискотек и вечеров отдыха, выставочный и бильярдный залы.</p><p> Визитной карточкой района является народный самодеятельный коллектив ансамбль русской песни. В 2021 году он отметил 45-летний юбилей. Гордостью является народный танцевальный коллектив «Северное сияние» – неоднократный лауреат различных межрайонных, областных, межрегиональных и всероссийских конкурсов. Развивается в ЦКР и театральное творчество. Полюбились вожегодцам спектакли театрального коллектива «Премьера». Популярностью пользуются кружки для детей: фитнес-студия «Здоровчики», арт-студия «Разноцветный мир», танцевальная студия «Апельсин», клубы «Веселый пешеход», «Зеленые защитники» и др.</p><p> Специалисты ЦКР проводят различные мероприятия, вожегодцы имеют возможность отдохнуть и принять в них самое активное участие. </p>', 'http://rdc-vozh.vgr.muzkult.ru', 'admin@vozhega.ru', '[{"value": "78174422647", "comment": ""}, {"value": "78174422155", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/9ace566e50cda441f7bf11edd823b187.jpg", "title": "28970663.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Вожегодский ЦКР»', 'Вожегодский район', 'Europe/Moscow', 'ул Садовая,д 10', NULL, 'обл Вологодская,р-н Вожегодский,рп Вожега,ул Садовая,д 10', NULL, 3506005231, 'mincult', 'Вожегодский район', 'Europe/Moscow', NULL, 26662, '[{"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 59899, '[{"url":"https://www.culture.ru/institutes/60129/vozhegodskii-centr-kulturnogo-razvitiya","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vozhega/dvorcy-kultury-i-kluby/71891pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=e646d6d3-6754-4209-b021-9d42a6803984&shareType=venue","serviceName":"ФанТам"}]', 59899, NULL, NULL, NULL, '2022-01-25 18:34:03+03', '2025-09-25 09:32:41+03', '0101000020E6100000A0DE8C9AAF1A44408046E9D2BF3C4E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Вожегодский центр традиционной народной культуры', 'Вожегодский район', 'Europe/Moscow', 'ул Транспортная,д 17', NULL, 'обл Вологодская,р-н Вожегодский,рп Вожега,ул Транспортная,д 17', '{"type": "Point", "coordinates": [40.214898, 60.475469]}', '<p>Центр основан 1 октября 2008 года. Он занимается восстановлением, сохранением, популяризацией традиционной народной культуры. В нем действует 19 клубных формирований, из них:</p><ul><li> 12 ремесленных отделений: ткачество, плетение поясов, кружевоплетение, вязание, лоскутное шитье, кройка и шитье, берестоплетение, ивоплетение, резьба по дереву, роспись по дереву, народная кукла, лепка из глины; </li><li>игра на гармошке;</li><li> творческая мастерская по народным ремеслам; </li><li>5 клубов по интересам: клуб ветеранов «Солнцеворот», семейный клуб, клуб «На кинопосиделках», «Ладушки, оладушки», «Русская душа». </li></ul><p>В клубных формированиях обеспечивается систематический режим занятий (2 раза в неделю для ремесленных отделений, 1 раз в месяц для клубов по интересам). </p><p>Разработаны программы по проведению мероприятий для детских садов, школьников, старшего поколения (из циклов «Бытовая культура Русского Севера», «Традиционная пища», «Праздники народного календаря»). Также проводятся мастер-классы по традиционным ремеслам, концерты, выставки, познавательно-развлекательные, игровые программы по традиционной народной культуре. За год проходит 400 мероприятий, посещений – 9 000 человек. </p><p>Одной из важных услуг центра является услуга по сохранению фонда фольклорно-этнографических материалов. В ходе исследовательской деятельности количество объектов нематериального культурного наследия составило 154 единицы хранения.</p>', 'http://ctnkvozhega.vlg.muzkult.ru', 'ctnk.vogega@mail.ru', '[{"value": "78174422511", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/cdc972af3bb98026e2f69fa12eace08e.jpeg", "title": "Центр))).jpg"}', '[{"url": "https://all.culture.ru/uploads/4804f05c6544d419a2399eb647fc1b35.jpg", "title": "ЦТНК.jpg"}, {"url": "https://all.culture.ru/uploads/27d4a5984a90e5c2411a0df5626179b4.jpg", "title": "bc3rnNnInVE.jpg"}, {"url": "https://all.culture.ru/uploads/a0057980d3383295f10b475144b846ca.jpg", "title": "зрит.зал.jpg"}, {"url": "https://all.culture.ru/uploads/4e428f1eb703f2282a0c976160b45529.jpg", "title": "rq-zhhnunsA.jpg"}, {"url": "https://all.culture.ru/uploads/4770270fe6cb54c89e456c58546847da.jpg", "title": "AmjQheUeBcA.jpg"}, {"url": "https://all.culture.ru/uploads/8db2ded26d4e3fdc88a3f4a2096108f7.jpg", "title": "_0lkvncMMQlY0f6M5mex0S3YsTzz0ziEcqz1v2tLMVPeXEa1_suRkahqC4qGiSYT5u5lmNHH6QxeDFuaiUy82UYX.jpg"}, {"url": "https://all.culture.ru/uploads/4d33af5f01c4c76136f96872d1f4fde9.jpg", "title": "N2ff1yYy5p3A_q872PFxmGwQeN1nWnJpPNk0gys1uVKTN76HsnCn0HlMKyfXAwegzBDvuEBwoGYMGejq7nQokXym.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МБУК «Вожегодский Центр традиционной народной культуры»', 'Вожегодский район', 'Europe/Moscow', 'ул Транспортная,17', NULL, 'обл Вологодская,р-н Вожегодский,рп Вожега,ул Транспортная,17', NULL, 3506004502, 'mincult', 'Вожегодский район', 'Europe/Moscow', '[{"network":"vk","name":"Галя Лобова","networkId":"111386215","updateDate":"2022-11-16T06:27:15Z","createDate":"2022-11-16T06:27:15Z","accountId":42954,"postingGroupId":37147},{"network":"vk","name":"МБУК \"Центр традиционной народной культуры\"","networkId":"66363769","updateDate":"2022-11-16T06:18:54Z","createDate":"2022-11-16T06:18:54Z","accountId":42954,"postingGroupId":37146},{"network":"ok","name":"Галина Лобова","networkId":"515527507442","updateDate":"2025-01-21T06:43:58Z","createDate":"2025-01-21T06:43:58Z","accountId":42637,"postingGroupId":47011},{"network":"ok","name":"ЦТНК Вожега","networkId":"70000001135858","updateDate":"2023-03-27T06:52:42Z","createDate":"2022-11-16T06:27:33Z","accountId":42637,"postingGroupId":37148}]', 20419, '[{"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 329, "name": "Ремесла и художественные промыслы", "sysName": "remesla-i-hudozhestvennye-promysly"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "17:15:00", "from": "08:00:00"}', '{"to": "17:15:00", "from": "08:00:00"}', '{"to": "17:15:00", "from": "08:00:00"}', '{"to": "17:15:00", "from": "08:00:00"}', '{"to": "16:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 58847, '[{"url":"https://www.culture.ru/institutes/57663/vozhegodskii-centr-tradicionnoi-narodnoi-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vozhega/dvorcy-kultury-i-kluby/61234pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=06850657-163d-485a-9b4d-b40bbc7e0094&shareType=venue","serviceName":"ФанТам"}]', 58847, NULL, NULL, NULL, '2021-12-14 11:04:24+03', '2025-10-02 11:27:44+03', '0101000020E6100000E7FC14C7811B444083A10E2BDC3C4E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Тарногский центр культурного развития', 'Тарногский район', 'Europe/Moscow', 'ул Советская,д 41', NULL, 'обл Вологодская,р-н Тарногский,с Тарногский Городок,ул Советская,д 41', '{"type": "Point", "coordinates": [43.567447, 60.499918]}', '<p><span>Здание Тарногского центра<span> </span>культуры – исторический объект, построенный руками активной молодежи села в 1966 году. Здесь есть зрительный зал на 350 мест, что позволяет проводить крупные районные мероприятия. </span></p> <p><span>На сегодняшний день в учреждении активно работает 46</span><span> <span> </span>клубных формирований, </span><span>которые во многом определяют сегодня культурную и духовную жизнь района. Из них <span></span>6 творческих коллективов имеют звание «народный», 1 творческое формирование – звание «образцовый». Это народный хор «Россияночка», народный театр, <span> </span>танцевальный коллектив «Радуга», <span> </span>вокальный ансамбль «Сияние», вокальный квартет «Ритм души», народный вокальный ансамбль "Кружева" ,образцовый детский театр-студия «Солнышко».<span> </span>Коллективы успешно выступают<span> </span>на областных и международных конкурсах.</span></p> <p><span>Дом культуры организовывает различные по форме и тематике культурно-массовые мероприятия: праздники, представления, фестивали, конкурсы, вечера отдыха, концерты, выставки, игровые развлекательные программы и другие формы показа результатов творческой деятельности клубных формирований.</span><span></span></p>', NULL, 'domkylltar@yandex.ru', '[{"value": "78174821163", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/a68b62bfe79c9fc9f5e1e5490a119150.jpeg", "title": "rV-ACiJqMC8.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК «Тарногский центр культурного развития» Тарногского муниципального района Вологодской области', 'Тарногский район', 'Europe/Moscow', 'ул Советская,д 41', NULL, 'обл Вологодская,р-н Тарногский,с Тарногский Городок,ул Советская,д 41', NULL, 3517003557, 'mincult', 'Тарногский район', 'Europe/Moscow', NULL, 17497, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "17:00:00", "from": "10:00:00"}', '{"to": "17:00:00", "from": "10:00:00"}', '{"to": "17:00:00", "from": "10:00:00"}', '{"to": "17:00:00", "from": "10:00:00"}', '{"to": "17:00:00", "from": "10:00:00"}', NULL, '{"to": "18:00:00", "from": "12:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 58711, '[{"url":"https://www.culture.ru/institutes/57266/tarnogskii-centr-kulturnogo-razvitiya","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/tarnogskiy-gorodok/dvorcy-kultury-i-kluby/61220pl","serviceName":"Афиша7"}]', 58711, NULL, NULL, NULL, '2021-12-07 14:06:09+03', '2025-09-17 17:14:55+03', '0101000020E61000004E9B711AA2C8454043572250FD3F4E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Новаторский клуб', 'Великоустюгский район', 'Europe/Moscow', 'ул Советская,д 1', NULL, 'обл Вологодская,р-н Великоустюгский,п Новатор,ул Советская,д 1', '{"type": "Point", "coordinates": [46.20147585185128, 60.74630787686369]}', '<p>В архивных фондах первое упоминание о клубе относится к 26 января 1924 года. Принято постановление о ремонте дома-дачи бывшего владельца фанерного завода И. Я. Львова, в дальнейшем использование первого этажа дома под рабочий клуб. К сожалению, здание клуба было утрачено в 1927 году в связи с пожаром. <br /></p><p> В 1975 году было начато строительство клубного помещения на 360 мест. В декабре 1979 года здание сдали в эксплуатацию. До 2000 года клуб был заводским. Клубная работа получила новый импульс, когда клуб был передан отделу культуры. Учреждение получило статус дома культуры. С 2005 года учредителем Новаторского дома культуры является администрация сельского поселения Самотовинское.</p><p><span>Дом культуры предоставляет широкий спектр услуг: концертные, конкурсно-развлекательные программы, шоу, литературно-музыкальные вечера, конкурсы и смотры.</span></p><p><span>В настоящее время в нем работают 16 кружков и клубов по интересам. Занимается 4 коллектива: ВИА «Старая пластинка», ансамбль русской песни «Журавушка», вокальный ансамбль «Сати», ансамбль ветеранов «С песней по жизни».</span></p>', 'http://novatordk.ru', 'novator_DK@mail.ru', '[{"value": "78173865837", "comment": "Голованова Евгения Владимировна"}, {"value": "79212363854", "comment": "начальник"}]', '{"url": "https://all.culture.ru/uploads/8500bf3e46c5cbdf8e6d9b24fa86a2fe.jpg", "title": "bZf8y2uFTf32VuE7mhWELfpSwMTYwKQgJ5eylbZI5BE04ZLCnRhuHI0yz48thR6uXWpYH6deCfHSyraQOr3K-pWm.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11:45:45Z","accountId":46589,"postingGroupId":41531},{"network":"vk","name":"\"Усть-Алексеевский клуб\"","networkId":"196143083","updateDate":"2023-04-05T13:11:25Z","createDate":"2023-04-05T13:11:25Z","accountId":46589,"postingGroupId":41534},{"network":"vk","name":"«Верхневарженский клуб»","networkId":"219499380","updateDate":"2023-04-05T11:45:28Z","createDate":"2023-04-05T11:45:28Z","accountId":46589,"postingGroupId":41530},{"network":"vk","name":"«Морозовский клуб»","networkId":"219948363","updateDate":"2023-07-05T08:23:07Z","createDate":"2023-07-05T08:23:07Z","accountId":46589,"postingGroupId":42638},{"network":"vk","name":"«Новаторский клуб»","networkId":"217628593","updateDate":"2023-03-17T08:05:55Z","createDate":"2023-03-17T08:05:55Z","accountId":46589,"postingGroupId":41030},{"network":"vk","name":"Анюта Красникова","networkId":"17613040","updateDate":"2023-03-17T10:43:29Z","createDate":"2023-03-17T10:43:29Z","accountId":46594,"postingGroupId":41037},{"network":"vk","name":"БУК \"Юдинский дом культуры\" п. Стрига 6а","networkId":"160210512","updateDate":"2023-04-11T12:03:48Z","createDate":"2023-04-11T12:03:48Z","accountId":46589,"postingGroupId":41660},{"network":"vk","name":"Великоустюгский культурно-досуговый центр","networkId":"117993849","updateDate":"2024-02-15T08:49:55Z","createDate":"2024-02-15T08:49:55Z","accountId":46589,"postingGroupId":44737},{"network":"vk","name":"Обособленное подразделение \"Аристовский клуб\"","networkId":"195948369","updateDate":"2023-03-17T08:06:12Z","createDate":"2023-03-17T08:06:12Z","accountId":46589,"postingGroupId":41031},{"network":"vk","name":"Обособленное подразделение \"Сусоловский клуб\"","networkId":"219106681","updateDate":"2023-04-07T11:43:09Z","createDate":"2023-04-07T11:43:09Z","accountId":46589,"postingGroupId":41581},{"network":"vk","name":"Обособленное подразделение \"Теплогорский клуб\"","networkId":"97047864","updateDate":"2023-04-07T11:43:26Z","createDate":"2023-04-07T11:43:26Z","accountId":46589,"postingGroupId":41582},{"network":"vk","name":"Окультурено молодежью","networkId":"199241624","updateDate":"2023-03-17T10:42:43Z","createDate":"2023-03-17T10:42:43Z","accountId":46594,"postingGroupId":41036},{"network":"vk","name":"Парк культуры и отдыха /Великий Устюг/","networkId":"153198570","updateDate":"2023-04-05T11:46:08Z","createDate":"2023-04-05T11:46:08Z","accountId":46589,"postingGroupId":41532},{"network":"vk","name":"Полдарский клуб","networkId":"206228726","updateDate":"2023-07-05T08:23:33Z","createDate":"2023-07-05T08:23:33Z","accountId":46589,"postingGroupId":42639},{"network":"vk","name":"Театр Деда Мороза","networkId":"199304892","updateDate":"2020-11-03T05:54:59Z","createDate":"2020-11-03T05:54:59Z","accountId":21245,"postingGroupId":30273}]', 20409, '[{"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 322, "name": "Хор", "sysName": "hor"}, {"id": 325, "name": "Творческий коллектив", "sysName": "tvorcheskiy-kollektiv"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 55718, '[{"url":"https://www.culture.ru/institutes/53437/novatorskii-klub","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/76387pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=7f2740b1-a01d-4aa2-b60a-e3ab3d220a09&shareType=venue","serviceName":"ФанТам"}]', 55718, NULL, NULL, NULL, '2021-07-14 10:22:32+03', '2025-09-24 16:11:25+03', '0101000020E61000004751F1F5C919474039F03904875F4E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Вохтожский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'ул Юбилейная,д 23', NULL, 'обл Вологодская,р-н Грязовецкий,пгт Вохтога,ул Юбилейная,д 23', '{"type": "Point", "coordinates": [41.03128692850588, 58.81453098578203]}', '<p> БУК ГМО ВО «Вохтожский поселковый Дом культуры» это общедоступный центр общения, духовного развития и активного отдыха населения поселка Вохтога. Основной деятельностью Дома культуры является предоставление населению разнообразных услуг социально-культурного, просветительского, оздоровительного и развлекательного характера, создание условий для занятий любительским художественным творчеством. Он был создан в 1982 году. Это двухэтажное здание с подвалом, в котором есть зрительный зал, фойе, помещения для отдыха и развлечений, лекционно-информационные и студийно-кружковые помещения. Зрительный зал рассчитан на 330 посадочных мест, предназначен для проведения концертов, спектаклей, торжественных, социально-значимых и других мероприятий.</p><p> </p>', 'http://vpdk.vlg.muzkult.ru', NULL, '[{"value": "78175531183", "comment": ""}, {"value": "78175531475", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/576148c6896b7a42485ab003b31d4f6e.jpeg", "title": "j6LIbs0mmGw.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК «Вохтожский ПДК»', 'Грязовецкий район', 'Europe/Moscow', 'ул Юбилейная,д 23', NULL, 'обл Вологодская,р-н Грязовецкий,пгт Вохтога,ул Юбилейная,д 23', NULL, 3509007974, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Вохтожский ПДК\"","networkId":"142709621","updateDate":"2023-06-03T06:04:17Z","createDate":"2023-06-03T06:04:17Z","accountId":44162,"postingGroupId":42507},{"network":"vk","name":"Ольга Фомичева","networkId":"146007613","updateDate":"2022-12-16T08:44:18Z","createDate":"2022-12-16T08:44:18Z","accountId":44162,"postingGroupId":38409},{"network":"vk","name":"Онлайн изостудия \"уDIVим\" БУК \"Вохтожский ПДК\"","networkId":"215937108","updateDate":"2022-12-16T08:44:44Z","createDate":"2022-12-16T08:44:44Z","accountId":44162,"postingGroupId":38410}]', 17457, '[{"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 52482, '[{"url":"https://www.culture.ru/institutes/57412/vokhtozhskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/61027pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=5e5d931d-7d98-4532-b0b9-4d8a5b5b9b9b&shareType=venue","serviceName":"ФанТам"}]', 52482, NULL, NULL, NULL, '2021-04-23 15:28:01+03', '2025-09-19 14:04:01+03', '0101000020E6100000CE5CC7350184444098C1248D42684D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Дворец культуры «Солдек»', 'Сокольский район', 'Europe/Moscow', 'ул Мусинского,д 4', NULL, 'обл Вологодская,р-н Сокольский,г Сокол,ул Мусинского,д 4', '{"type": "Point", "coordinates": [40.080151, 59.465055]}', '<p>Дворец культуры «Солдек» открылся 27 апреля 1964 года. Находится он в одноименном микрорайоне города Сокола. Во дворце всей семьей можно посетить дни семейного отдыха – традиционные праздники с увлекательными конкурсами и играми, интерактивными программами и концертами. В «Солдеке» проходят праздничные концерты в зрительном зале и под открытым небом. </p><p>В живом исполнении звучат всеми любимые хиты, танцевальные композиции и музыкальные эксперименты. Для детей проводятся развлекательно-познавательные интерактивные программы, на которых в игровой форме ребята узнают много нового. Для молодежи «Солдек» стал площадкой конкурсов и фестивалей, где молодое поколение проявляет свои таланты, развлекается и находит единомышленников. </p><p>Люди элегантного возраста заряжаются энергией и «возвращаются» в старые добрые времена на «Хобби-классах». В центральном фойе «Солдека» проводятся выставки фотографий, изобразительного и декоративно-прикладного искусства.</p>', 'http://дк-солдек.рф', 'dksoldek@gmail.com', '[{"value": "78173334028", "comment": "специалисты"}, {"value": "78173334041", "comment": "директор"}]', '{"url": "https://all.culture.ru/uploads/de5475fc645cdd5a81bce95bdf8264e4.jpeg", "title": "2A0H_2dpoNQ.jpg"}', '[{"url": "https://all.culture.ru/uploads/4d853952b9b199810fe7ed954f8b4450.jpeg", "title": "AlFK2sib6cM.jpg"}, {"url": "https://all.culture.ru/uploads/a02d19499da65faf0c30b534f1cf4a92.jpeg", "title": "IMG_8979.JPG"}, {"url": "https://all.culture.ru/uploads/eb519d2960f526a62541ab2e9434d8a3.jpg", "title": "LZ-kz49FaIBJKNu3F6RFc8YdXGGATErg7ACU8xT9H5v3epVg1XLkI-iNuCQQGIl7G1popV9Wcq1Tk0yT4urldiW2.jpg"}, {"url": "https://all.culture.ru/uploads/18862685915b465e7a3bb816b4098d62.jpg", "title": "oG9zfbc8ep5qF5D_zc95aZCVdidkchXPDkzXjFpf1b6u3TEQnQNs-gke9DY56SiuS318yWtAp43j9OnJBjiGlZ1s.jpg"}, {"url": "https://all.culture.ru/uploads/b7e78f5286773335ca003c1bf47387ce.jpg", "title": "Ai6rKqKQ8W3NnO_DW3POb1WX6Ak6-5hDiMeL0PjA_gFqoZ6ZBiDNqYdCXQkG6LjYoedULBDfw2MA3YiEgy6DWaNu.jpg"}, {"url": "https://all.culture.ru/uploads/4b37d2810d6a393efe5baaa7728f80d1.jpg", "title": "ChjeNB-3SNtf9uZCsq9hJwJ8WZzs7DqIDKxcZrJb5KIA97ap7sw6QdAX2OyZkAgWBwH4XcE33r5TQa0M7I_p4C04.jpg"}, {"url": "https://all.culture.ru/uploads/fd7b37321d053dac293546bbee469351.jpg", "title": "ZAp8vaaeynlwiiLTxlgVG4jNdEwWxGFUz0nfq7WjICiBrS9jjx08M_Zb_LngmKRFsAYw8BLizcLbvC8LhHjndqN8.jpg"}]', NULL, 'Дворцы культуры и клубы', 'БУК СМО ДК «Солдек»', 'Сокольский район', 'Europe/Moscow', 'ул Мусинского,д 4', NULL, 'обл Вологодская,р-н Сокольский,г Сокол,ул Мусинского,д 4', NULL, 3527020720, 'mincult', 'Сокольский район', 'Europe/Moscow', '[{"network":"vk","name":"БУК СМО Дворец культуры «Солдек»","networkId":"206116624","updateDate":"2024-08-08T08:23:28Z","createDate":"2024-08-08T08:23:28Z","accountId":28111,"postingGroupId":45974},{"network":"vk","name":"Бук-Смр-Дворец-Культуры Солдек","networkId":"563318189","isPersonal":true,"updateDate":"2019-12-04T06:07:33Z","createDate":"2019-12-04T06:07:33Z","accountId":28111,"postingGroupId":25499}]', 16971, '[{"id": 122, "name": "Искусство", "sysName": "iskusstvo"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 40914, '[{"url":"https://www.culture.ru/institutes/41357/dvorec-kultury-soldek","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/sokol/dvorcy-kultury-i-kluby/22450pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=04f4dfb2-de8e-4063-9f20-10a97d8cb98f&shareType=venue","serviceName":"ФанТам"},{"serviceName":"Культурная афиша (ВКонтакте)"}]', 40914, NULL, NULL, NULL, '2019-12-04 15:11:25+03', '2025-09-04 09:44:12+03', '0101000020E6100000F0DE5163420A4440AFEB17EC86BB4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Центр традиционной народной культуры «Лад»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 89', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 89', '{"type": "Point", "coordinates": [46.301182, 60.76058]}', '<p>Центр традиционной народной культуры «Лад» основан в 2008 году, в нем разработаны и успешно реализуются<span> </span>долгосрочные проекты:<span> </span>«Шемогодская береста», «Живая нить традиций», «Кружевная сказка».</p> <p><span>Большое внимание уделяется возрождению<span> </span>самобытных народных промыслов и ремесел. Около 140 мастеров города и района сотрудничают с отделом. Сотрудники восстанавливают традиции многих местных ремесел: различные виды ткачества, плетения поясов, вышивки, кружевоплетения, народной куклы, росписи и резьбы по бересте и др.</span></p><p><span><span> </span>Мастера передают свой опыт молодому поколению. При отделе созданы объединения великоустюгских<span> </span>мастериц: «Великоустюгские узоры» (роспись),<span> </span>«Шемогодские узоры» (резьба по бересте) и «Кружевная сказка» (кружевоплетение). </span></p> <p><span> Центр традиционной народной культуры реализует творческие программы и проекты – фестивали, праздники, конкурсы, выставки:</span></p><ul><li><span><span> </span></span><span>«</span><span>Круглый год</span><span>»;</span></li><li><span>«</span><span>Традиции через века</span><span>»;</span></li><li><span></span><span>«</span><span>Зимняя сказка</span><span>»;</span></li><li><span>«</span><span>Кружево из белой бересты</span><span>»;</span></li><li><span>«</span><span>Узоры Севера</span><span>»;</span><span></span></li><li><span></span><span>«</span><span>Пасхальный вернисаж</span><span>»;</span><span></span></li><li><span>«</span><span>Мастер золотые руки</span><span>» и другие. </span></li></ul> <p>Из числа сотрудников отдела создан фольклорный коллектив «Ромода», в котором специалисты изучают местную музыкальную культуру и воспроизводят ее. <span>Для молодых устюжан открыты клубные объединения по освоению местных промыслов и<span> </span>ремесел –</span><span> 20 клубных формирований.</span></p> <p><span> </span>В течение года для устюжан и гостей города проходят игровые театрализованные программы по народному календарю: «Рождественские посиделки», «Праздник Масленицы», «Осенины», «Покровские посиделки», «Кузьминки».</p> <p><span> </span></p>', 'http://кдцву.рф', 'ztnk_lad73@mail.ru', '[{"value": "78173821006", "comment": ""}, {"value": "78173823192", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/09ed544628fcf618c0ce8828df479a73.jpeg", "title": "rKbl0OcCego.jpg"}', '[{"url": "https://all.culture.ru/uploads/30a2c27d36a701c8248322676f0d089d.jpeg", "title": "D-UsNQ2-IsI.jpg"}, {"url": "https://all.culture.ru/uploads/c30bc087f4c8e2423af7b1731a88015d.jpeg", "title": "iU3_-ccIMJA.jpg"}, {"url": "https://all.culture.ru/uploads/46ab0b71d8a4aade84fd01691767cfa8.jpeg", "title": "y7QdCLg0A3k.jpg"}, {"url": "https://all.culture.ru/uploads/a03271d226fb5e3db11b22ad1a2bd33d.jpeg", "title": "uWjBEFG9IuA.jpg"}, {"url": "https://all.culture.ru/uploads/891f3740273eda8d12985977c1fec7df.jpeg", "title": "f_vPAViPVqo.jpg"}, {"url": "https://all.culture.ru/uploads/89c556949704939e33ef1e622e5a3cb4.jpeg", "title": "xHAdkebBPkE.jpg"}, {"url": "https://all.culture.ru/uploads/0b3e98a7650fc8ae84c6c569093630da.jpeg", "title": "ix8YUc_sMP8.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11:45:45Z","accountId":46589,"postingGroupId":41531},{"network":"vk","name":"\"Усть-Алексеевский клуб\"","networkId":"