:43Z","createDate":"2023-03-17T10:42:43Z","accountId":46594,"postingGroupId":41036},{"network":"vk","name":"Парк культуры и отдыха /Великий Устюг/","networkId":"153198570","updateDate":"2023-04-05T11:46:08Z","createDate":"2023-04-05T11:46:08Z","accountId":46589,"postingGroupId":41532},{"network":"vk","name":"Полдарский клуб","networkId":"206228726","updateDate":"2023-07-05T08:23:33Z","createDate":"2023-07-05T08:23:33Z","accountId":46589,"postingGroupId":42639},{"network":"vk","name":"Театр Деда Мороза","networkId":"199304892","updateDate":"2020-11-03T05:54:59Z","createDate":"2020-11-03T05:54:59Z","accountId":21245,"postingGroupId":30273}]', 20409, '[{"id": 321, "name": "Традиции", "sysName": "tradicii"}, {"id": 324, "name": "Традиционное искусство", "sysName": "tradicionnoe-iskusstvo"}, {"id": 152, "name": "Этнография", "sysName": "etnografiya"}, {"id": 206, "name": "Народное творчество", "sysName": "narodnoe-tvorchestvo"}, {"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 329, "name": "Ремесла и художественные промыслы", "sysName": "remesla-i-hudozhestvennye-promysly"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', '[{"hosting":"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-117993849&id=456239175&hash=6f032d93ab2abd4d&hd=2\" width=\"853\" height=\"480\" frameborder=\"0\" allowfullscreen></iframe>"}]', '{"to": "17:00:00", "from": "08:00:00"}', '{"to": "17:00:00", "from": "08:00:00"}', '{"to": "17:00:00", "from": "08:00:00"}', '{"to": "17:00:00", "from": "08:00:00"}', '{"to": "17:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 39071, '[{"url":"https://www.culture.ru/institutes/54044/centr-tradicionnoi-narodnoi-kultury-lad","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/57597pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=579aa68c-1c62-44fd-b