INSERT INTO culture_data.culture_palaces_clubs VALUES ('Культурно-досуговый центр «Северный»', 'Череповец', 'Europe/Moscow', 'ул Спортивная,д 13', NULL, 'обл Вологодская,г Череповец,ул Спортивная,д 13', '{"type": "Point", "coordinates": [37.952815, 59.141602]}', '<p>Дворец культуры «Северный» был создан в 1990 году по инициативе Череповецкого фанерно-мебельного комбината для жителей Северного района города Череповца. В 1996 году ДК был передан Управлению по делам культуры мэрии г. Череповца. В 2014 году ДК «Северный» был присоединен в качестве структурного подразделения ко Дворцу культуры «Строитель» имени Д. Н. Мамлеева и переименован в Культурно-досуговый центр «Северный».</p><p>На базе КДЦ «Северный» свою деятельность осуществляют творческие коллективы хореографического, вокального, циркового и театрального направлений, а также студия английского языка.</p> <p>В настоящее время КДЦ «Северный» имеет два зала: зрительный и дискозал. Современное световое и звуковое оборудование, деревянная сцена, наличие хореографических и репетиционных залов позволяют предложить населению многочисленный спектр услуг. В залах с большим успехом проводятся театрализованные праздники, дискотеки, вечера отдыха, детские развлекательные программы, концерты и представления. </p>', NULL, NULL, '[{"value": "78202290737", "comment": "Директор центра"}, {"value": "78202291838"}]', '{"url": "https://all.culture.ru/uploads/f8b2a6b78830a0340eebbc1218800d21.jpg", "title": "северный.jpg"}', '[{"url": "https://all.culture.ru/uploads/c7e97b883f556602cb47681ac8ecf29b.jpeg", "title": "AGkxSwKM6Ak.jpg"}, {"url": "https://all.culture.ru/uploads/035424736970407051046fa475e47be4.jpeg", "title": "i9fIEigP14c.jpg"}, {"url": "https://all.culture.ru/uploads/eb4c589ec5ade47a3d4a4858aac62c71.jpeg", "title": "HwCLJC7BQwE.jpg"}, {"url": "https://all.culture.ru/uploads/9769d13dc4e881c54bff9f4aaa9b5f31.jpeg", "title": "NBDXFZomkD8.jpg"}, {"url": "https://all.culture.ru/uploads/04e4546914d034d391f7325c4bd742ec.jpeg", "title": "X9UaPZc-93Q.jpg"}, {"url": "https://all.culture.ru/uploads/4a08f10b530fd33cc7de012e18a3d06f.jpeg", "title": "VGnnMx9cJPA.jpg"}, {"url": "https://all.culture.ru/uploads/13a6344d430b1164ef28e825a6936d4b.jpeg", "title": "uoDoPzuc3VQ.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МАУК ДК «Строитель» имени Д.Н. Мамлеева', 'Череповец', 'Europe/Moscow', 'Площадь Строителей,1', NULL, 'обл Вологодская,г Череповец,Площадь Строителей,1', NULL, 3528011172, 'mincult', 'Череповец', 'Europe/Moscow', '[{"network":"vk","name":"Дворец культуры \"Строитель\" имени Д.Н. Мамлеева","networkId":"79973007","updateDate":"2021-04-07T12:54:41Z","createDate":"2021-04-07T12:54:41Z","accountId":36583,"postingGroupId":33432}]', 20189, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 38764, '[{"url":"https://www.culture.ru/institutes/56570/kulturno-dosugovyi-centr-severnyi","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/dvorcy-kultury-i-kluby/77002pl","serviceName":"Афиша7"}]', 38764, NULL, NULL, NULL, '2019-04-17 12:41:56+03', '2025-09-24 15:53:15+03', '0101000020E6100000B21188D7F5F942402B86AB0320924D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Дом культуры льнокомбината', 'Вологда', 'Europe/Moscow', 'ул Космонавта Беляева,д 9', NULL, 'обл Вологодская,г Вологда,ул Космонавта Беляева,д 9', '{"type": "Point", "coordinates": [39.919748, 59.195076]}', '<p>13 июня 1939 года в День текстильщика было торжество и народное гулянье по поводу открытия Дома культуры льнокомбината. В это время льнокомбинат был построен, но еще не выпускал продукцию, а клуб уже действовал. Во время Великой Отечественной войны в Доме культуры в зрительном зале жили вывезенные из блокады ленинградцы. </p><p>В настоящее время в <span>учреждении</span> работают семь творческих коллективов, шесть из которых имеют звание «народный» или «образцовый». Коллективы – обладатели Гран-при и лауреаты международных, всероссийских и региональных фестивалей и конкурсов. </p><p> Дом культуры объединяет в своих стенах дошколят и ветеранов труда Великой Отечественной войны, они приходят заниматься творчеством.</p>', 'https://gdk.vlg.muzkult.ru/dkl', 'dkl_2009@mail.ru', '[{"value": "78172747459"}]', '{"url": "https://all.culture.ru/uploads/51c19a78cb94e8915a10cb56d5017c6e.jpeg", "title": "Ehf15Vw_xWQ.jpg"}', '[{"url": "https://all.culture.ru/uploads/268d7e75330dfb65320ae08c0ab24c8d.jpeg", "title": "4xUpwYkDajs.jpg"}, {"url": "https://all.culture.ru/uploads/ff35d01c315f8fe5f569496a5ee8b26a.jpeg", "title": "79lGRxuuBd0.jpg"}, {"url": "https://all.culture.ru/uploads/f2cab8d3a2ddc307c1dfd3e16b482e58.jpeg", "title": "qD8EVVhIYbY.jpg"}, {"url": "https://all.culture.ru/uploads/8b487275888f0ee80e7ba1a80aee3fc8.jpeg", "title": "qJy3QOtQjE8.jpg"}, {"url": "https://all.culture.ru/uploads/945087211d417dd426b81b09ce301057.jpeg", "title": "X-IMJDBVH20.jpg"}, {"url": "https://all.culture.ru/uploads/3ab5c5ce4a04e2e86c1610712a150c39.jpeg", "title": "iAF0UixOAeg.jpg"}, {"url": "https://all.culture.ru/uploads/bf3c0c70bbe4493df8f305fed554c8ab.jpeg", "title": "wb60ldomQSQ.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МУК «ГДК» г.Вологды', 'Вологда', 'Europe/Moscow', 'ул Ленина,д 17', NULL, 'обл Вологодская,г Вологда,ул Ленина,д 17', NULL, 3525036933, 'mincult', 'Вологда', 'Europe/Moscow', '[{"network":"vk","name":"МУК \"ГДК\" г.Вологды","networkId":"6643997","updateDate":"2023-10-12T09:43:34Z","createDate":"2023-10-12T09:43:34Z","accountId":48825,"postingGroupId":43552}]', 20247, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 38468, '[{"url":"https://www.culture.ru/institutes/49918/dom-kultury-lnokombinata","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vologda/dvorcy-kultury-i-kluby/46982pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=bb1a7887-9d24-4615-9c86-9106a7c10f6d&shareType=venue","serviceName":"ФанТам"}]', 38468, NULL, NULL, NULL, '2019-04-10 13:54:28+03', '2025-09-08 15:27:42+03', '0101000020E6100000DC476E4DBAF54340041E1840F8984D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Городской Дворец культуры г.Вологды', 'Вологда', 'Europe/Moscow', 'ул Ленина,д 17', NULL, 'обл Вологодская,г Вологда,ул Ленина,д 17', '{"type": "Point", "coordinates": [39.898458, 59.221758]}', '<p>Дворец культуры Вологды – это учреждение культуры, образованное в 1962 году, когда на левом берегу реки Вологды распахнул двери новый тогда еще Дом культуры с концертным залом, библиотекой, комнатами для кружковой работы и репетиций. В настоящее время он является ведущим учреждением по организации культурного досуга населения города, на территории которого проживают 301 740 человек. </p><p>Во Дворце культуры регулярно проходят концерты, фестивали-конкурсы, спектакли, выставки, вечера отдыха, театрализованные представления, тематические и познавательные программы. Успешно работает более 20 творческих коллективов, из них 13 имеют звание «Народный самодеятельный коллектив», 5 – «Образцовый художественный коллектив». Ежегодно коллективы и их участники становятся обладателями Гран-при и лауреатами международных, всероссийских, областных, городских фестивалей и конкурсов. </p><p> </p>', 'https://gdk.vlg.muzkult.ru/about', 'gdkvologda@mail.ru', '[{"value": "78172724258"}]', '{"url": "https://all.culture.ru/uploads/88e480ad95420b6eed2e2f3ed3b6d8ba.jpg", "title": "5OgOKGZkzWndeWUbWmaqWBXqJmu_VRVlhNvALd4gXtoXToqwAJlve9Vajmc-2k4dBsglAaM8w9oMmf4e7sTl6sbN.jpg"}', '[{"url": "https://all.culture.ru/uploads/aedc3d783d06a517870e654205d9c477.jpeg", "title": "oom5FkAnRKQ.jpg"}, {"url": "https://all.culture.ru/uploads/e6e2b1193d765a9be6819d996896453d.jpeg", "title": "rIbXOUmrCS8_1.jpg"}, {"url": "https://all.culture.ru/uploads/3fe5c63234785756adc642d279a177fe.jpeg", "title": "image_image_396271.jpg"}, {"url": "https://all.culture.ru/uploads/cb672915c32c6f672e62eba069cc7022.jpeg", "title": "image_image_3860995.JPG"}, {"url": "https://all.culture.ru/uploads/c74f933c0c6d422ae9bec5823dcd3b9c.jpeg", "title": "7VLOE-YidJ8.jpg"}, {"url": "https://all.culture.ru/uploads/75b9387225796b3f72e1bac9ec66c9ea.jpeg", "title": "ifIvwF9U32k.jpg"}, {"url": "https://all.culture.ru/uploads/626b9e8cf5667721d6037ad2dac35343.jpeg", "title": "P1280074.JPG"}]', NULL, 'Дворцы культуры и клубы', 'МУК «ГДК» г.Вологды', 'Вологда', 'Europe/Moscow', 'ул Ленина,д 17', NULL, 'обл Вологодская,г Вологда,ул Ленина,д 17', NULL, 3525036933, 'mincult', 'Вологда', 'Europe/Moscow', '[{"network":"vk","name":"МУК \"ГДК\" г.Вологды","networkId":"6643997","updateDate":"2023-10-12T09:43:34Z","createDate":"2023-10-12T09:43:34Z","accountId":48825,"postingGroupId":43552}]', 20247, '[{"id": 122, "name": "Искусство", "sysName": "iskusstvo"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', '{"to": "22:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 38467, '[{"url":"https://www.culture.ru/institutes/49553/gorodskoi-dvorec-kultury-g-vologdy","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vologda/dvorcy-kultury-i-kluby/46347pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=b1971255-96d7-4de6-9a99-20cef4894f94&shareType=venue","serviceName":"ФанТам"}]', 38467, NULL, NULL, NULL, '2019-04-10 13:47:21+03', '2025-09-08 15:27:57+03', '0101000020E61000002F6AF7AB00F343402DD0EE90629C4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Бабаевский центр культурного развития', 'Бабаевский район', 'Europe/Moscow', 'пл Привокзальная,д 1', NULL, 'обл Вологодская,р-н Бабаевский,г Бабаево,пл Привокзальная,д 1', '{"type": "Point", "coordinates": [35.94657427976227, 59.387036260503145]}', '<p>Первый концерт в Бабаевском районном доме культуры состоялся 7 ноября 1949 года. Эта дата является днем основания Бабаевского центра культурного развития. </p><p>В настоящее время сложилась целая программа давно полюбившихся горожанам мероприятий. Это народные гулянья, концерты, фестивали, акции, ярмарки, праздничные и юбилейные вечера города, творческие вечера, детские игровые программы, интеллектуальные игры, занятия в любительских клубах и объединениях и другое.</p><p>В настоящее время в составе ЦКР более 15 творческих коллективов и объединений:</p><ol><li>Народный коллектив вокальная группа «Колпь» – постоянный участник городских и районных мероприятий, конкурсов, концертов.</li><li> Народный хор «Русская песня». Репертуар хорового коллектива разнообразен: русские народные песни, песни советских и современных авторов. В программе – произведения двух- и трехголосного звучания, а также песни а капелла.</li><li> Народный коллектив вокальная группа «Радуга».</li><li> Народный театр.</li><li><span> Образцовая театральная студия «Фиеста». </span><span>Занятия проходят по различным направлениям: актерское мастерство, сценическая речь, основы пальчикового и кукольного театра, сказкотерапия и многое другое.</span></li><li>Вокально-эстрадная группа «Камертон». Участники студии – многократные победители творческих конкурсов, в т. ч. международных.</li></ol><p></p>', NULL, 'babaevo_kdc@mail.ru', '[{"value": "78174321096", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/a84fcd523c46fc46c307fe4d840fb732.jpg", "title": "11111.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МАУК «Бабаевский центр культурного развития»', 'Бабаевский район', 'Europe/Moscow', 'пл Привокзальная,1', NULL, 'обл Вологодская,р-н Бабаевский,г Бабаево,пл Привокзальная,1', NULL, 3501008870, 'mincult', 'Бабаевский район', 'Europe/Moscow', '[{"network":"vk","name":"Володинский Дом культуры","networkId":"158838778","updateDate":"2018-10-12T11:09:38Z","createDate":"2018-10-12T11:09:38Z","accountId":22721,"postingGroupId":20087},{"network":"vk","name":"Кдц Бабаево","networkId":"275144982","isPersonal":true,"updateDate":"2018-10-12T11:09:46Z","createDate":"2018-10-12T11:09:46Z","accountId":22721,"postingGroupId":20088},{"network":"vk","name":"МБУК \"Бабаевский центр культурного развития\"","networkId":"23582611","updateDate":"2018-10-12T11:09:31Z","createDate":"2018-10-12T11:09:31Z","accountId":22721,"postingGroupId":20086}]', 20369, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 36065, '[{"url":"https://afisha7.ru/babaevo/dvorcy-kultury-i-kluby/60906pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/55792/babaevskii-centr-kulturnogo-razvitiya","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=604086f1-84d8-4c33-bc18-11e31d34a2d3&shareType=venue","serviceName":"ФанТам"}]', 36065, NULL, NULL, NULL, '2018-10-12 14:25:34+03', '2025-09-04 10:33:45+03', '0101000020E61000002768935829F94140139D78678AB14D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Центр культурного развития г. Кириллова', 'Кирилловский район', 'Europe/Moscow', 'ул Гагарина,д 98', NULL, 'обл Вологодская,р-н Кирилловский,г Кириллов,ул Гагарина,д 98', '{"type": "Point", "coordinates": [38.374511, 59.856985]}', '<p>Центр культурного развития работает с января 2015 года. Это центр досуга с большим объемом и разными формами работы, направленными на развитие духовности и общей культуры населения. </p><p>Центр культурного развития, как и все клубные учреждения, сегодня является местом, где собираются дети, молодежь, взрослые для общения, отдыха и организации своего досуга. Двери открыты для всех, кто хочет принять участие в мероприятиях, принести пользу своему городу и району и украсить свой досуг. Здесь есть большой уютный зрительный зал, кружковые комнаты. Коллектив строит свою деятельность, используя множество форм культурно-массовой работы с учетом возрастных особенностей населения. </p><p>На базе учреждения работают более 30 клубных формирований различной направленности. Четыре коллектива имеют звание «Народный самодеятельный коллектив». Это ансамбль народной песни «Светла горница», ансамбль «Северные фрески», Кирилловский народный театр, казачий ансамбль «Серебряная подкова».</p>', 'https://rdk-kirillov.vlg.muzkult.ru', 'zhagaliak@rambler.ru', '[{"value": "78175744207", "comment": ""}, {"value": "78175744208", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/582dc818076357509ac31e183328a567.jpg", "title": "DSC_0541 (2).jpg"}', '[{"url": "https://all.culture.ru/uploads/636e290f3e0ee49c15099d2a37270a4c.jpg", "title": "oKbp1VLsJYA.jpg"}]', NULL, 'Дворцы культуры и клубы', 'АУК КМР «ЦКР»', 'Кирилловский район', 'Europe/Moscow', 'ул Гагарина,д 98', NULL, 'обл Вологодская,р-н Кирилловский,г Кириллов,ул Гагарина,д 98', NULL, 3511006791, 'mincult', 'Кирилловский район', 'Europe/Moscow', '[{"network":"vk","name":"Центр культурного развития","networkId":"17831631","updateDate":"2018-05-29T07:22:36Z","createDate":"2018-05-29T07:22:36Z","accountId":21387,"postingGroupId":18946}]', 20401, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "20:00:00", "from": "10:00:00"}', '{"to": "20:00:00", "from": "10:00:00"}', '{"to": "20:00:00", "from": "10:00:00"}', '{"to": "20:00:00", "from": "10:00:00"}', '{"to": "20:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35092, '[{"url":"https://www.culture.ru/institutes/55187/centr-kulturnogo-razvitiya-g-kirillova","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/kirillov/dvorcy-kultury-i-kluby/73270pl","serviceName":"Афиша7"}]', 35092, NULL, NULL, NULL, '2018-05-29 10:32:37+03', '2025-09-16 14:13:11+03', '0101000020E6100000027FF8F9EF2F4340CF143AAFB1ED4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Великоустюгский культурно-досуговый центр', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', 'центральный вход с пер. Красный, д. 8', 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', '{"type": "Point", "coordinates": [46.303527, 60.759561]}', '<p><span style="vertical-align:inherit">За более 60 лет творческой деятельности коллектив Дома культуры прошел большой путь. Формировались вкусы, оттачивалось мастерство, рождались и крепли традиции.</span></p><p>В настоящее время в центре работают 43 клубных формирования – это клубы по интересам, коллективы художественной самодеятельности, кружки прикладного творчества: 6 вокальных клубных формирований, 5 танцевальных, цирковое, 4 любительских объединения. Из них половина занимается на бесплатной основе.</p><p>Более 500 мероприятий в год проводится на базе культурно-досугового центра, в которых принимают участие и коллективы учреждений, и приглашенные артисты из других регионов. </p><p><span>Великоустюгский культурно-досуговый центр не <span>остается</span> в стороне от всероссийского проекта «Великий Устюг – родина Деда Мороза» и принимает активное участие в реализации этой программы.</span></p>', 'http://кдцву.рф', 'vukdc@vumr.ru', '[{"value": "78173823192", "comment": "директор - Ирина Сергеевна Зубова"}, {"value": "78173823050", "comment": "заместитель директора по творческой деятельности - Светлана Павловна Корепина"}]', '{"url": "https://all.culture.ru/uploads/5f86dd9f24591db71c1116c65a2c6286.jpeg", "title": "fasad.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11:45:45Z","accountId":46589,"postingGroupId":41531},{"network":"vk","name":"\"Усть-Алексеевский клуб\"","networkId":"196143083","updateDate":"2023-04-05T13:11:25Z","createDate":"2023-04-05T13:11:25Z","accountId":46589,"postingGroupId":41534},{"network":"vk","name":"«Верхневарженский клуб»","networkId":"219499380","updateDate":"2023-04-05T11:45:28Z","createDate":"2023-04-05T11:45:28Z","accountId":46589,"postingGroupId":41530},{"network":"vk","name":"«Морозовский клуб»","networkId":"219948363","updateDate":"2023-07-05T08:23:07Z","createDate":"2023-07-05T08:23:07Z","accountId":46589,"postingGroupId":42638},{"network":"vk","name":"«Новаторский клуб»","networkId":"217628593","updateDate":"2023-03-17T08:05:55Z","createDate":"2023-03-17T08:05:55Z","accountId":46589,"postingGroupId":41030},{"network":"vk","name":"Анюта Красникова","networkId":"17613040","updateDate":"2023-03-17T10:43:29Z","createDate":"2023-03-17T10:43:29Z","accountId":46594,"postingGroupId":41037},{"network":"vk","name":"БУК \"Юдинский дом культуры\" п. Стрига 6а","networkId":"160210512","updateDate":"2023-04-11T12:03:48Z","createDate":"2023-04-11T12:03:48Z","accountId":46589,"postingGroupId":41660},{"network":"vk","name":"Великоустюгский культурно-досуговый центр","networkId":"117993849","updateDate":"2024-02-15T08:49:55Z","createDate":"2024-02-15T08:49:55Z","accountId":46589,"postingGroupId":44737},{"network":"vk","name":"Обособленное подразделение \"Аристовский клуб\"","networkId":"195948369","updateDate":"2023-03-17T08:06:12Z","createDate":"2023-03-17T08:06:12Z","accountId":46589,"postingGroupId":41031},{"network":"vk","name":"Обособленное подразделение \"Сусоловский клуб\"","networkId":"219106681","updateDate":"2023-04-07T11:43:09Z","createDate":"2023-04-07T11:43:09Z","accountId":46589,"postingGroupId":41581},{"network":"vk","name":"Обособленное подразделение \"Теплогорский клуб\"","networkId":"97047864","updateDate":"2023-04-07T11:43:26Z","createDate":"2023-04-07T11:43:26Z","accountId":46589,"postingGroupId":41582},{"network":"vk","name":"Окультурено молодежью","networkId":"199241624","updateDate":"2023-03-17T10:42:43Z","createDate":"2023-03-17T10:42:43Z","accountId":46594,"postingGroupId":41036},{"network":"vk","name":"Парк культуры и отдыха /Великий Устюг/","networkId":"153198570","updateDate":"2023-04-05T11:46:08Z","createDate":"2023-04-05T11:46:08Z","accountId":46589,"postingGroupId":41532},{"network":"vk","name":"Полдарский клуб","networkId":"206228726","updateDate":"2023-07-05T08:23:33Z","createDate":"2023-07-05T08:23:33Z","accountId":46589,"postingGroupId":42639},{"network":"vk","name":"Театр Деда Мороза","networkId":"199304892","updateDate":"2020-11-03T05:54:59Z","createDate":"2020-11-03T05:54:59Z","accountId":21245,"postingGroupId":30273}]', 20409, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 329, "name": "Ремесла и художественные промыслы", "sysName": "remesla-i-hudozhestvennye-promysly"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "21:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35091, '[{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/19164pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/36136/velikoustyugskii-kulturno-dosugovyi-centr","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=686b45a7-9457-4ee6-b96d-96542fdb6698&shareType=venue","serviceName":"ФанТам"}]', 35091, NULL, NULL, NULL, '2018-05-29 10:28:59+03', '2025-09-03 10:17:30+03', '0101000020E6100000FC3905F9D926474095287B4B39614E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Верховажский культурно-досуговый центр', 'Верховажский район', 'Europe/Moscow', 'ул Стебенева,д 41', NULL, 'обл Вологодская,р-н Верховажский,с Верховажье,ул Стебенева,д 41', '{"type": "Point", "coordinates": [42.04816460609436, 60.74643010954224]}', '<p>Верховажский культурно-досуговый центр Верховажского муниципального округа Вологодской области (Верховажский районный Дом культуры) находится в центре села Верховажье и размещен в двухэтажном современном здании на 320 посадочных мест, введенное в эксплуатацию в 1984 году.</p><p>Дом культуры со дня своего открытия, является объединяющим центром творческих, талантливых и увлеченных людей всех возрастов. Это территория непосредственного живого общения, где встречаются люди, объединенные общими интересами. Здесь работают детские, молодежные, ветеранские коллективы самодеятельного творчества, клубные формирования, любительские объединения. Работники учреждения регулярно участвуют в выездных мероприятиях в малонаселенные и отдаленные населенные пункты Верховажского муниципального округа.</p><p>В течение творческого сезона в Верховажском культурно-досуговом центре проходят тематические представления, концерты, конкурсы, спектакли, театрализованные представления, народные гуляния, фестивали самодеятельного творчества, танцевальные вечера, показ кинофильмов и др.</p> <p></p><p><span> Верховажский культурно-досуговый центр всегда открыт для творчества, созидания, сотрудничества.</span></p><p><span> Директор – Светлана Клавдиевна Борцова.</span></p>', 'https://vrdk.vlg.muzkult.ru', 'vrdk@mail.ru', '[{"value": "78175921986", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/39d98573fe885d160a22c5baf04c7598.jpg", "title": "фасад.jpg"}', '[{"url": "https://all.culture.ru/uploads/3eddecbf7c2cdd8aca16c8d068f5f599.jpg", "title": "20220121_133306.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МБУК «Верховажский культурно-досуговый центр»', 'Верховажский район', 'Europe/Moscow', 'ул Стебенева,д 41', NULL, 'обл Вологодская,р-н Верховажский,с Верховажье,ул Стебенева,д 41', NULL, 3505005849, 'mincult', 'Верховажский район', 'Europe/Moscow', '[{"network":"vk","name":"МБУК Верховажский КДЦ","networkId":"92555483","updateDate":"2024-03-14T10:25:25Z","createDate":"2024-03-14T10:25:25Z","accountId":50172,"postingGroupId":44974}]', 20423, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 753, "name": "Кинозал", "sysName": "kinozal"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 34948, '[{"url":"https://afisha7.ru/verhovazhe/dvorcy-kultury-i-kluby/80097pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/36035/verkhovazhskii-kulturno-dosugovyi-centr","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=82c44a1c-8466-4bf4-803a-18579e15e437&shareType=venue","serviceName":"ФанТам"}]', 34948, NULL, NULL, NULL, '2018-05-16 09:22:01+03', '2025-09-09 12:05:59+03', '0101000020E6100000000000422A064540E79D96058B5F4E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Центр культурного развития г. Вологды', 'Вологда', 'Europe/Moscow', 'ул Машиностроительная,д 26', 'ост. «Судоремонтная»', 'обл Вологодская,г Вологда,ул Машиностроительная,д 26', '{"type": "Point", "coordinates": [39.922003, 59.208751]}', '<p>Дом культуры «Речник» был основан в 2009 году. Он поменял свое название 25 июля 2018 года на Центр культурного развития Вологды. </p><p> В учреждении проходят различные культурно-массовые мероприятия: вечера-встречи, кружковая деятельность, концерты, конкурсы-фестивали, конкурсы детского творчества, различные тематические праздники и шоу-программы. Центр культурного развития имеет собственные традиционные мероприятия и мастерские народного творчества.</p><p> Ежегодно проводится набор в студии. Это четыре народных самодеятельных коллектива: танцевальная студия «Серпантин», студия ирландского танца «Тинкерс», хор русской песни «Реченька», театральная студия «Визави». Также Заслуженный коллектив народного творчества Российской Федерации Ансамбль народного танца «Русская душа». В центре работает изостудия, вокальная студия, студия игры на гитаре, творческие мастерские.</p>', 'https://rechnik.vlg.muzkult.ru', 'rechnik83@mail.ru', '[{"value": "79210648636", "comment": ""}, {"value": "78172277980", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/73fddc29b8a59b6c5a6aed6f0f41aee6.jpg", "title": "87172bc3b70407bea97c9441186a3abb_w2048_h2048.jpg"}', '[{"url": "https://all.culture.ru/uploads/c7e6a551cf3d7dad080a801e11a19b5e.jpg", "title": "3.jpg"}, {"url": "https://all.culture.ru/uploads/8108429e4154346a8a5e8a2cdd7f0633.jpg", "title": "12.jpg"}, {"url": "https://all.culture.ru/uploads/3858864707942ebd9c6d8178692533de.jpg", "title": "13.jpg"}, {"url": "https://all.culture.ru/uploads/9803153872780284718deb06b140ad39.jpg", "title": "2.jpg"}, {"url": "https://all.culture.ru/uploads/ca8b40045310ce0efdab56adb1cb59fc.jpg", "title": "9.jpg"}, {"url": "https://all.culture.ru/uploads/da32cd32bae7cf3b11890bc33c8da59e.jpg", "title": "11.jpg"}, {"url": "https://all.culture.ru/uploads/ba8c6685dfcaf6722a3cd4c66120e7f0.JPG", "title": "DSC_0731.JPG"}]', NULL, 'Дворцы культуры и клубы', 'МАУК «Центр культурного развития г. Вологды»', 'Вологда', 'Europe/Moscow', 'ул Машиностроительная,д 26', NULL, 'обл Вологодская,г Вологда,ул Машиностроительная,д 26', NULL, 3525230144, 'mincult', 'Вологда', 'Europe/Moscow', '[{"network":"vk","name":"Анна Речникова","networkId":"433487639","updateDate":"2023-11-17T09:15:55Z","createDate":"2023-11-17T09:15:55Z","accountId":21233,"postingGroupId":43960},{"network":"vk","name":"Ансамбль народной песни \"Медуница\" (г. Вологда)","networkId":"200469053","updateDate":"2023-11-17T09:21:46Z","createDate":"2023-11-17T09:21:46Z","accountId":21233,"postingGroupId":43968},{"network":"vk","name":"Волонтёрский отряд ЦКР г. Вологды","networkId":"165529039","updateDate":"2023-11-17T09:21:10Z","createDate":"2023-11-17T09:21:10Z","accountId":21233,"postingGroupId":43961},{"network":"vk","name":"Декоративно - прикладное творчество","networkId":"203337157","updateDate":"2023-11-17T09:21:20Z","createDate":"2023-11-17T09:21:20Z","accountId":21233,"postingGroupId":43963},{"network":"vk","name":"МАУК «ЦКР г. Вологды» (ДК «Речник»)","networkId":"44217358","updateDate":"2023-08-01T12:17:26Z","createDate":"2023-08-01T12:17:26Z","accountId":21233,"postingGroupId":42874},{"network":"vk","name":"НСК Танцевальная студия «Серпантин»","networkId":"210705154","updateDate":"2023-11-17T09:21:26Z","createDate":"2023-11-17T09:21:26Z","accountId":21233,"postingGroupId":43964},{"network":"vk","name":"НСК Хор русской песни \"Реченька\"","networkId":"196555290","updateDate":"2023-11-17T09:21:35Z","createDate":"2023-11-17T09:21:35Z","accountId":21233,"postingGroupId":43966},{"network":"vk","name":"Студия вокала «МЕЧТА»|Вологда","networkId":"206242585","updateDate":"2023-11-17T09:21:31Z","createDate":"2023-11-17T09:21:31Z","accountId":21233,"postingGroupId":43965},{"network":"vk","name":"Студия игры на гитаре?Вологда","networkId":"206858928","updateDate":"2023-11-17T09:21:15Z","createDate":"2023-11-17T09:21:15Z","accountId":21233,"postingGroupId":43962},{"network":"vk","name":"Студия изобразительного искусства?Вологда","networkId":"206859132","updateDate":"2023-11-17T09:21:41Z","createDate":"2023-11-17T09:21:41Z","accountId":21233,"postingGroupId":43967}]', 20392, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 34902, '[{"url":"https://www.culture.ru/institutes/36420/centr-kulturnogo-razvitiya-g-vologdy","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vologda/dvorcy-kultury-i-kluby/19150pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=dc331498-7e13-4d86-9dd6-6823396eaadd&shareType=venue","serviceName":"ФанТам"}]', 34902, NULL, NULL, NULL, '2018-05-14 15:09:48+03', '2025-09-03 09:31:23+03', '0101000020E61000002DE8BD3104F64340EF004F5AB89A4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Дворец культуры «Строитель» им. Д. Н. Мамлеева', 'Череповец', 'Europe/Moscow', 'пл Строителей,д 1', NULL, 'обл Вологодская,г Череповец,пл Строителей,д 1', '{"type": "Point", "coordinates": [37.8828, 59.123915]}', '<p><span>Дворец культуры «Строитель» имени Д. Н. Мамлеева </span><span>является одним из крупнейших культурных центров досуга Вологодской области. Он</span><span> ведет свою историю с 1954 года. В 1967 году открылось </span><span>дополнительное здание – пристройка с большим концертным залом, </span><span>кабинетами для кружковой работы и репетиций. </span><span>В 2008 году осуществлен капитальный ремонт здания, </span><span>созданы благоприятные и комфортные условия для посетителей.</span></p><p><span>В настоящее время Дворец культуры имеет два концертных зала: </span><span>большой концертный зал на 755 мест, малый концертный зал на 210 мест. </span><span>Современное световое и звуковое оборудование, технические параметры сцены, </span><span>наличие хореографических и репетиционных залов позволяют </span><span>предложить населению многочисленный спектр услуг.</span></p><p><span>В залах с большим успехом проводятся театрализованные праздники, </span><span>дискотеки, вечера отдыха, детские развлекательные программы, </span><span>выставки, концерты и представления. </span><span>Площадка Дворца культуры является местом проведения городских и областных торжеств, </span><span>гастролей профессиональных коллективов.</span></p><p><span>В 2014 году ДК «Строитель» был реорганизован </span><span>в форме присоединения к нему в качестве структурного подразделения – </span><span>Культурно-досугового центра «Северный».</span></p>', 'http://dkstroitel35.ru', 'priemnaya@dks35.ru', '[{"value": "78202255914", "comment": "приемная директора"}, {"value": "78202255233", "comment": "вахта (круглосуточно)"}]', '{"url": "https://all.culture.ru/uploads/c8c91ac18421508b5958a701f85ba195.jpg", "title": "207314828.jpg"}', '[{"url": "https://all.culture.ru/uploads/f753bc955d9fb38b5fac8a47c9f59897.JPG", "title": "Большой концертный зал.JPG"}, {"url": "https://all.culture.ru/uploads/d21734eec8c3b2674115181c289754b1.jpg", "title": "fr0L-qc6NdU.jpg"}, {"url": "https://all.culture.ru/uploads/dfd474fad692a40dac834e808210e630.jpg", "title": "ДКС_01.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МАУК ДК «Строитель» имени Д.Н. Мамлеева', 'Череповец', 'Europe/Moscow', 'Площадь Строителей,1', NULL, 'обл Вологодская,г Череповец,Площадь Строителей,1', NULL, 3528011172, 'mincult', 'Череповец', 'Europe/Moscow', '[{"network":"vk","name":"Дворец культуры \"Строитель\" имени Д.Н. Мамлеева","networkId":"79973007","updateDate":"2021-04-07T12:54:41Z","createDate":"2021-04-07T12:54:41Z","accountId":36583,"postingGroupId":33432}]', 20189, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 191, "name": "Творчество", "sysName": "tvorchestvo"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 34488, '[{"url":"https://www.culture.ru/institutes/35776/dvorec-kultury-stroitel-im-d-n-mamleeva","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/dvorcy-kultury-i-kluby/18868pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=983c6b13-2d80-4663-b1e9-aacb3aab262b&shareType=venue","serviceName":"ФанТам"}]', 34488, NULL, NULL, NULL, '2018-04-13 12:13:33+03', '2025-09-24 17:32:50+03', '0101000020E610000054742497FFF04240EE3D5C72DC8F4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Дворец химиков г. Череповца', 'Череповец', 'Europe/Moscow', 'пр-кт Победы,д 100', 'авт. № 1, 2, 3, 5, 8, 12, 13, 18, 31', 'обл Вологодская,г Череповец,пр-кт Победы,д 100', '{"type": "Point", "coordinates": [37.962337, 59.125208]}', '<p>Дворец является правопреемником городского Дома культуры, созданного в 1946 году. В 1992 году реорганизован в Городской дворец культуры «Аммофос» и в августе 2013 года переименован в Дворец химиков.</p><p>Дворец химиков – один из основных организаторов и исполнителей городских, культурно-массовых праздников, представляет следующие услуги:<br />* Выступление творческих коллективов Дворца на массовых мероприятиях и городских праздниках, участие в сольных концертных программах и театрализованных представлениях Дворца;<br />* Развитие творческих способностей детей, подростков и взрослых (театральное искусство, современная хореография, бальные танцы, эстрадный вокал, классический вокал);<br />* Услуги для образовательных учреждений. Дворец химиков – это отличное место, где воспитанники детских садов и школьники могут познавательно и интересно провести свой досуг. <br /></p><p>В настоящее время во Дворце культуры действуют творческие коллективы:</p><ul><li>творческий центр эстрады «Ветер Live»;</li><li>студия современной хореографии и балет «Хобби»;</li><li>школа искусств и балет «Синергия»;</li><li>танцевальный клуб «Бомонд»; </li><li>танцевальный клуб «Ритм»;</li><li>цирк «Антре»;</li><li>народный драматический театр;</li><li>народная вокальная студия;</li><li>детская театральная студия «Фламинго»;</li><li>ансамбль «Бабье лето».</li></ul> <p>Творческие коллективы принимают активное участие в культурных мероприятиях области, посвященных государственным и профессиональным праздникам, а также в реализации проектов федерального значения. </p>', 'https://dh35.ru', 'dk-himikov@ya.ru', '[{"value": "78202281880", "comment": ""}, {"value": "79216853755", "comment": "Весна Елена, специалист по связям с общественностью"}]', '{"url": "https://all.culture.ru/uploads/68df03a01e95637f82d8a5193f40a68a.jpg", "title": "himik.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МАУК «Дворец химиков»', 'Череповец', 'Europe/Moscow', 'пр-кт Победы,д 100', NULL, 'обл Вологодская,г Череповец,пр-кт Победы,д 100', NULL, 3528012497, 'mincult', 'Череповец', 'Europe/Moscow', '[{"network":"vk","name":"Андрей КУРСАКОВ (Певец)","networkId":"46476437","updateDate":"2022-11-17T23:53:51Z","createDate":"2022-11-17T23:53:51Z","accountId":43066,"postingGroupId":37248},{"network":"vk","name":"Андрей Курсаков","networkId":"10460926","updateDate":"2022-11-17T23:55:03Z","createDate":"2022-11-17T23:55:03Z","accountId":43066,"postingGroupId":37250},{"network":"vk","name":"Дворец химиков г.Череповец","networkId":"28552807","updateDate":"2018-04-11T13:55:25Z","createDate":"2018-04-11T13:55:25Z","accountId":20751,"postingGroupId":18377},{"network":"vk","name":"Рок-фестиваль \"Время колокольчиков\"","networkId":"215724898","updateDate":"2023-10-19T16:31:06Z","createDate":"2023-10-19T16:31:06Z","accountId":43066,"postingGroupId":43637},{"network":"vk","name":"Фестиваль-конкурс \"Голос Череповца\"","networkId":"212352436","updateDate":"2022-11-17T23:54:06Z","createDate":"2022-11-17T23:54:06Z","accountId":43066,"postingGroupId":37249}]', 20167, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', '{"to": "23:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 34431, '[{"url":"https://www.culture.ru/institutes/35805/dvorec-khimikov-g-cherepovca","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/dvorcy-kultury-i-kluby/18829pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=8f466cd7-040d-4a00-a567-82cc527ed2f0&shareType=venue","serviceName":"ФанТам"}]', 34431, NULL, NULL, NULL, '2018-04-11 18:19:54+03', '2025-09-16 15:08:29+03', '0101000020E6100000895DDBDB2DFB42404A99D4D006904D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Чагодощенский дом культуры', 'Чагодощенский район', 'Europe/Moscow', 'ул Кирова,д 5', NULL, 'обл Вологодская,р-н Чагодощенский,рп Чагода,ул Кирова,д 5', '{"type": "Point", "coordinates": [35.336094, 59.167888]}', '<p>Здание, в котором располагается учреждение, было построено в 1948 году. Чагодощенский дом культуры – это центр культурной жизни, а также главная концертная площадка округа. Здесь проводятся все основные районные праздничные мероприятия: концерты, смотры, выставки, спектакли, юбилеи, фестивали, творческие встречи, конкурсы, а также вечера отдыха, дискотеки, лекции, киносеансы, детские утренники. </p><p>Учреждение занимается организацией досуга не только жителей, но и гостей района. В Доме культуры работают кружки, студии, клубные формирования, любительские объединения по культурно-познавательным, художественно-творческим и иным интересам.</p>', 'https://chagodadk.esgms.ru', 'Chagodardk@bk.ru', '[{"value": "78174121238", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/6379a83be5f45b0e43a9b95bd24e00dd.jpg", "title": "5O2Q4Ix_IH0.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУ «Чагодощенский районный дом культуры»', 'Чагодощенский район', 'Europe/Moscow', 'ул Кирова,д 5', NULL, 'обл Вологодская,р-н Чагодощенский,п Чагода,ул Кирова,д 5', NULL, 3522001481, 'mincult', 'Чагодощенский район', 'Europe/Moscow', NULL, 20453, '[{"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 792, "name": "Участникам СВО", "sysName": "uchastnikam-svo"}, {"id": 25, "name": "Классическое искусство", "sysName": "klassicheskoe-iskusstvo"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 79274, '[{"url":"https://www.culture.ru/institutes/92113/chagodoshenskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/chagoda/dvorcy-kultury-i-kluby/100179pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=f0c63a9e-7fd7-4efd-8130-a3527ee67a06&shareType=venue","serviceName":"ФанТам"}]', 79274, NULL, NULL, NULL, '2023-04-25 18:51:30+03', '2025-10-31 13:01:29+03', '0101000020E6100000E030D12005AB414007B29E5A7D954D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Центр культурного развития с. Шуйского', 'Междуреченский район', 'Europe/Moscow', 'ул Советская,д 12', NULL, 'обл Вологодская,р-н Междуреченский,с Шуйское,ул Советская,д 12', '{"type": "Point", "coordinates": [41.025423275589525, 59.37437934510924]}', '<p>Центр культурного развития начал свою историю в 1960 году.  В Центре культурного развития проходят мероприятия различного уровня и направленности: районные торжественные вечера, массовые народные гулянья, детские игровые программы, дни рождения, тематические вечера, встречи для людей старшего возраста, дискотеки для подростков и молодежи, сельские ярмарки, конкурсные программы, праздники и концертные программы. В рамках туристического маршрута бренда «Междуречье – клюквенный край» на базе учреждения проводится интерактивная игровая программа «В гостях у Клюковки». На площадке центра проходят гастрольные мероприятия театральных, концертных и прочих коллективов области, других регионов. На базе учреждения действуют творческие коллективы: вокальные ансамбли «Девчата», «Криницы», народный самодеятельный вокальный ансамбль «Купава». </p><p><span></span></p> ', 'https://kultura60.ru/', 'kultura.60@mail.ru', '[{"value": "78174921417", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/980763ae19c49333b97fd2a8ba9cf926.jpg", "title": "ЦКР вх..jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК ММР «Центр культурного развития»', 'Междуреченский район', 'Europe/Moscow', 'ул Советская,12', NULL, 'обл Вологодская,р-н Междуреченский,с Шуйское,ул Советская,12', NULL, 3513003690, 'mincult', 'Междуреченский район', 'Europe/Moscow', '[{"network":"vk","name":"БУК ММО \"Центр культурного развития\"","networkId":"116053663","updateDate":"2023-07-19T08:26:04Z","createDate":"2023-07-19T08:26:04Z","accountId":48099,"postingGroupId":42785}]', 20410, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 751, "name": "Культура для школьников", "sysName": "kultura-dlya-shkolnikov"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "18:15:00", "from": "09:00:00"}', '{"to": "18:15:00", "from": "09:00:00"}', '{"to": "18:15:00", "from": "09:00:00"}', '{"to": "18:15:00", "from": "09:00:00"}', '{"to": "18:15:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 77553, '[{"url":"https://www.culture.ru/institutes/90423/centr-kulturnogo-razvitiya-s-shuiskogo","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/shuyskoe/dvorcy-kultury-i-kluby/96866pl","serviceName":"Афиша7"}]', 77553, NULL, NULL, NULL, '2023-03-10 08:13:17+03', '2025-10-20 10:22:42+03', '0101000020E61000006B9BE4114183444063C591A9EBAF4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Чернецкий сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'ул Центральная,д 47', NULL, 'обл Вологодская,р-н Грязовецкий,д Скородумка,ул Центральная,д 47', '{"type": "Point", "coordinates": [40.01615954886525, 58.86367138054447]}', '<p>Дом культуры является культурным центром д. Скородумка, располагается в большом кирпичном здании 1988 года постройки, а под культурно-досуговую деятельность выделено 10 помещений, включая зрительный и танцевальный зал.</p><p>Учреждение пользуется большой популярностью у местных жителей. Здесь проводится более 200 мероприятий в год, работают творческие и спортивные кружки для детей и людей старшего поколения, занимаются вокальные и хореографические коллективы. Ежегодно дом культуры становится площадкой для проведения межпоселенческого фестиваля патриотической песни «Война и песня» и открытого фестиваля «Круче всех». </p><p>Участники художественной самодеятельности успешно представляют района на областных конкурсах.</p><p>Одним из главных направлений работы дома культуры является привлечение людей старшего поколения к активной культурной жизни, разнообразие их досуга.</p>', NULL, 'mocrova.nata@yandex.ru', '[{"value": "78175559288"}]', '{"url": "https://all.culture.ru/uploads/dbbc23fa8219464d3332ba8c85be7fd6.jpg", "title": "IMG_20221201_111121 (1).jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 73714, '[{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/88517pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/86796/cherneckii-selskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=82d12ca9-8c82-4b53-87d7-4d95740a62c0&shareType=venue","serviceName":"ФанТам"}]', 73714, NULL, NULL, NULL, '2022-12-02 16:25:45+03', '2025-10-31 11:50:19+03', '0101000020E61000007AF21E8411024440FFF6A6C88C6E4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Ведерковский сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'ул Центральная,д 9', NULL, 'обл Вологодская,р-н Грязовецкий,д Бушуиха,ул Центральная,д 9', '{"type": "Point", "coordinates": [40.38892, 59.081738]}', '<p>Ведерковский сельский дом культуры был основан в 1979 году и по сей день является центром культурной жизни деревни. Здесь занимаются все возрастные группы, есть и хореографическое отделение, и класс вокала, и развивающие занятия для самых юных. </p><p>В 2016 году на базе Ведерковского сельского дома культуры был образован вокальный ансамбль «Серпантин» – участник районных и региональных конкурсов и фестивалей. Самые юные посетители занимаются в коллективах «Карамельки» и «Непоседы», для подростков ведет деятельность коллектив «Ассорти». Хорошие результаты показывает и вокальный коллектив «Русская душа». </p>', NULL, 'shigina.nataliya@yandex.ru', '[{"value": "79814322977"}]', '{"url": "https://all.culture.ru/uploads/54b26dcfff8790334ded6b63070c622b.jpg", "title": "1.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 73688, '[{"url":"https://www.culture.ru/institutes/86768/vederkovskii-selskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/89259pl","serviceName":"Афиша7"}]', 73688, NULL, NULL, NULL, '2022-12-02 12:57:42+03', '2025-10-31 17:49:00+03', '0101000020E610000052616C21C8314440946B0A64768A4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Ростиловский сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'ул Молодежная,д 4', NULL, 'обл Вологодская,р-н Грязовецкий,д Ростилово,ул Молодежная,д 4', '{"type": "Point", "coordinates": [40.264737, 58.800297]}', '<p>Ростиловский сельский дом культуры основан в 1968 году, с тех пор пользуется огромным спросом среди жителей не только деревни Ростилово, но и близлежащих населенных пунктов. Творческая жизнь Дома культуры очень насыщена и разнообразна: здесь есть и кружки по различным интересам, и клубные формирования, общая численность посетителей в которых – 366 человек. </p><p>Регулярно проводятся праздничные концерты, театральные постановки, а также фестивали и конкурсы для односельчан и жителей Грязовецкого муниципального района. Особенно популярен хореографический ансамбль «Стиль», который становится лауреатом конкурсов различного уровня.</p>', NULL, 'dom.kultury.rostilovo@mail.ru', '[{"value": "78175554292"}]', '{"url": "https://all.culture.ru/uploads/0cd863e359479af84cc437b381ef7ac6.jpg", "title": "EBeKaWvYWWg.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 73653, '[{"url":"https://www.culture.ru/institutes/86737/rostilovskii-selskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/88510pl","serviceName":"Афиша7"}]', 73653, NULL, NULL, NULL, '2022-12-01 16:55:14+03', '2025-10-31 17:47:56+03', '0101000020E61000004485EAE6E2214440200BD12170664D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Дом культуры п. Шексна', 'Шекснинский район', 'Europe/Moscow', 'ул Октябрьская,д 54', NULL, 'обл Вологодская,р-н Шекснинский,рп Шексна,ул Октябрьская,д 54', '{"type": "Point", "coordinates": [38.509924313944154, 59.205824367339304]}', '<p><span>В Доме культуры поселка Шексна организована работа известных творческих коллективов (заслуженный коллектив «Хор ветеранов ДК», мужской вокальный ансамбль и вокальный ансамбль «Энергия», вокальная студия «Калейдоскоп», детский образцовый хореографический ансамбль «Ритм», хореографический ансамбль «Серебряные нити», театральные студии «Маска» и «Чебурашка»), работа кружков и клубов по интересам, ведется творческая работа с солистами. </span><span>Функционируют клубные формирования, в которых задействованы и дети, и взрослые. </span></p> <p><span>Творческие коллективы принимают </span>участие в районных, областных, всероссийских конкурсах, фестивалях, в выездных концертах, в<span> </span>мероприятиях разных направлений деятельности, проводимых не только на территории поселка, но и в других муниципальных районах области.</p> <p><span>На базе Дома культуры ежегодно проводится</span><span> районный фестиваль творчества ветеранов «Родники российских деревень», районный конкурс вокального творчества «Две звезды», шоу-проект «Битва хоров», районный праздник труда и другие значимые мероприятия. </span></p>', 'https://sh-cks.vlg.muzkult.ru', 'dk.sheksna@yandex.ru', '[{"value": "78175121182", "comment": ""}, {"value": "78175121945", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/746e8b0604ae37d14995b2dbe3a45efd.jpg", "title": "ДК п. Шексна.jpg"}', '[{"url": "https://all.culture.ru/uploads/2b1d37314306c696df8f848fe8ccb758.jpeg", "title": "j_DXHbhpQa0.jpg"}, {"url": "https://all.culture.ru/uploads/c6a987fe9fbc87a917e8eca60e161b5b.jpeg", "title": "OtVwCFMc1fU.jpg"}, {"url": "https://all.culture.ru/uploads/686b680d7cf73d328ec221a1a16caa63.jpeg", "title": "qDmlvNurQCE.jpg"}]', NULL, 'Дворцы культуры и клубы', 'БУК Шекснинского МР «Централизованная клубная система»', 'Шекснинский район', 'Europe/Moscow', 'ул Октябрьская,д 54', NULL, 'обл Вологодская,р-н Шекснинский,рп Шексна,ул Октябрьская,д 54', NULL, 3524010925, 'mincult', 'Шекснинский район', 'Europe/Moscow', NULL, 17383, '[{"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "16:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 53256, '[{"url":"https://www.culture.ru/institutes/77516/dom-kultury-p-sheksna","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/sheksna/dvorcy-kultury-i-kluby/75409pl","serviceName":"Афиша7"}]', 53256, NULL, NULL, NULL, '2021-05-11 15:20:18+03', '2025-10-16 11:41:45+03', '0101000020E6100000A6E92D33454143409A38EF73589A4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Усть-Кубинский центр культуры и библиотечного обслуживания', 'Усть-Кубинский район', 'Europe/Moscow', 'ул Профсоюзная,д 2', NULL, 'обл Вологодская,р-н Усть-Кубинский,с Устье,ул Профсоюзная,д 2', '{"type": "Point", "coordinates": [39.72643, 59.627338]}', '<p style="margin-left:0px">Усть-Кубинский центр культуры и библиотечного обслуживания был построен в 2006 году. <span>Площадь</span><span> здания – 1 511,9 кв. м. Актовый зал вмещает до 360 зрителей</span>. </p><p style="margin-left:0px">Ежегодно коллектив учреждения проводит множество концертов, конкурсных программ, спектаклей, театрализованных представлений, осуществляются различные проекты. <span>На базе центра действуют </span>34 <span>клубных формирования, в которых занимаются 513 человек. 2</span> коллектива имеют звание «народный». </p> <p><span>Специалисты и руководители коллективов ведут постоянную работу по улучшению качества услуг, результатом которой становится успешное участие ансамблей центра в фестивалях и конкурсах различного уровня.</span></p>', NULL, NULL, '[]', '{"url": "https://all.culture.ru/uploads/45230cc3032664317fa941c27fa81ff4.jpg", "title": "ДК1.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'Муниципальное учреждение «Усть-Кубинский центр культуры и библиотечного обслуживания»', 'Усть-Кубинский район', 'Europe/Moscow', 'ул Профсоюзная,д 2', NULL, 'обл Вологодская,р-н Усть-Кубинский,с Устье,ул Профсоюзная,д 2', NULL, 3519004468, 'mincult', 'Усть-Кубинский район', 'Europe/Moscow', '[{"network":"vk","name":"Калейдоскоп творчества","networkId":"195726151","updateDate":"2021-04-15T09:19:03Z","createDate":"2021-04-15T09:19:03Z","accountId":36942,"postingGroupId":33755}]', 16766, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "17:15:00", "from": "09:00:00"}', '{"to": "17:15:00", "from": "09:00:00"}', '{"to": "17:15:00", "from": "09:00:00"}', '{"to": "17:15:00", "from": "09:00:00"}', '{"to": "17:15:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 25585, '[{"url":"https://www.culture.ru/institutes/57812/ust-kubinskii-centr-kultury-i-bibliotechnogo-obsluzhivaniya","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/uste/dvorcy-kultury-i-kluby/60856pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=ea038fc5-b35e-4ed1-8d66-f54ac2f68c1f&shareType=venue","serviceName":"ФанТам"}]', 25585, NULL, NULL, NULL, '2016-10-25 10:10:42+03', '2025-10-07 17:38:35+03', '0101000020E6100000A96A82A8FBDC4340DFC4909C4CD04D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Вашкинский районный дом культуры', 'Вашкинский район', 'Europe/Moscow', 'пер Парковый,д 12', NULL, 'обл Вологодская,р-н Вашкинский,с Липин Бор,пер Парковый,д 12', '{"type": "Point", "coordinates": [37.9684, 60.261475]}', '<p><span><span>Здание Вашкинского районного дома культуры </span>построено в 1982 году<span> по типовому проекту со спортивным залом и зрительным залом. В зоне обслуживания учреждения проживает около 4 000 человек. </span></span></p> <p><span>Дом культуры является главной сценической площадкой района, на которой проводятся значимые районные мероприятия, межрегиональные и зональные фестивали и конкурсы. На высоком профессиональном уровне работают многие творческие коллективы Дома культуры, которые достойно представляют район на областных фестивалях. Регулярно с концертными программами выступают прославленные коллективы<span> государственных учреждений культуры Вологодской области.</span></span></p>', 'https://vdk.vlg.muzkult', 'lipinbor.dk@mail.ru', '[]', '{"url": "https://all.culture.ru/uploads/c1188ef8972455d4de22b20d34e1e610.jpg", "title": "РДК.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК «Вашкинский районный Дом культуры»', 'Вашкинский район', 'Europe/Moscow', 'пер Парковый,д 12', NULL, 'обл Вологодская,р-н Вашкинский,с Липин Бор,пер Парковый,д 12', NULL, 3504025930, 'mincult', 'Вашкинский район', 'Europe/Moscow', NULL, 15145, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "19:00:00", "from": "09:00:00"}', '{"to": "19:00:00", "from": "09:00:00"}', '{"to": "19:00:00", "from": "09:00:00"}', '{"to": "19:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "11:00:00"}', '{"to": "18:00:00", "from": "11:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 22612, '[{"url":"https://afisha7.ru/lipin-bor/dvorcy-kultury-i-kluby/60840pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/61312/vashkinskii-raionnyi-dom-kultury","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=8b29d02a-11b6-4f20-a2c0-baad7a897520&shareType=venue","serviceName":"ФанТам"}]', 22612, NULL, NULL, NULL, '2016-08-19 16:58:08+03', '2025-10-07 16:02:48+03', '0101000020E610000024B9FC87F4FB42405DDC460378214E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Минькинский сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'ул Новая,д 61', NULL, 'обл Вологодская,р-н Грязовецкий,с Минькино,ул Новая,д 61', '{"type": "Point", "coordinates": [39.755509, 58.962201]}', '<p>Минькинский дом культуры был основан в 1981 году, с тех пор является центром культурной жизни села.</p><p>В Доме культуры занимается порядка 50 односельчан в 10 клубных формированиях. Основными направлениями деятельности филиала являются вокал, хореография, театральное мастерство и декоративно-прикладное творчество.</p><p>Регулярно здесь проходят акции, мастер-классы, праздничные программы, патриотические концерты, фестивали и конкурсы как среди местных жителей, так и среди гостей из близлежащих населенных пунктов, а в последнее время Минькинский сельский дом культуры стал для односельчан любимым местом проведения детских игровых программ.</p><p></p><p>Заведующая филиалом – Наталья Алексеевна Ломтева.</p>', NULL, 'nat.lomteva2014@yandex.ru', '[{"value": "78175550243"}]', '{"url": "https://all.culture.ru/uploads/ea93270fb2d446d2bb80179b0c44fcb4.jpg", "title": "20221007_134449.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 25, "name": "Классическое искусство", "sysName": "klassicheskoe-iskusstvo"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 79404, '[{"url":"https://www.culture.ru/institutes/92238/minkinskii-selskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/100365pl","serviceName":"Афиша7"}]', 79404, NULL, NULL, NULL, '2023-05-03 15:26:09+03', '2025-11-06 17:49:52+03', '0101000020E6100000B66AD784B4E04340D9960167297B4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Обнорский сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'д 67', NULL, 'обл Вологодская,р-н Грязовецкий,д Вараксино,д 67', '{"type": "Point", "coordinates": [40.442891, 58.606085]}', '<p>Обнорский сельский дом культуры был основан в 1979 году, с тех пор является центром культурной жизни деревень Вараксино, Батово и близлежащих поселков.</p><p>В Доме культуры занимается порядка 100 односельчан в 11 клубных формированиях. Основными направлениями деятельности филиала являются вокал, хореография, театральное мастерство и декоративно-прикладное творчество.</p><p>Регулярно здесь проходят мастер-классы, праздничные программы, патриотические концерты, фестивали и конкурсы как среди местных жителей, так и среди гостей из близлежащих населенных пунктов.</p><p></p><p>Заведующая филиалом – Светлана Николаевна Мосина.</p>', NULL, 'mosina.69@internet.ru', '[{"value": "79626723727"}]', '{"url": "https://all.culture.ru/uploads/65bc27792768d807888f1fddc5b82a64.jpg", "title": "Ts05fyQfNvs.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 26, "name": "Современное искусство", "sysName": "sovremennoe-iskusstvo"}, {"id": 25, "name": "Классическое искусство", "sysName": "klassicheskoe-iskusstvo"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 79397, '[{"url":"https://www.culture.ru/institutes/92232/obnorskii-selskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/100358pl","serviceName":"Афиша7"}]', 79397, NULL, NULL, NULL, '2023-05-03 12:05:20+03', '2025-11-06 16:44:44+03', '0101000020E6100000AC58FCA6B03844404FCC7A31944D4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Слободской сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'ул Школьная,д 5а', NULL, 'обл Вологодская,р-н Грязовецкий,д Слобода,ул Школьная,д 5а', '{"type": "Point", "coordinates": [40.231032, 58.958485]}', '<p><span>Слободской сельский дом культуры работает с 1973 года. Для культурно-досуговой деятельности оборудованы танцевальный, хореографический, зрительный залы, а также кружковая комната и методический кабинет. Зрительный зал рассчитан на 144 посадочных места.</span><br /></p> <p><span><span>В филиале для населения работают клубные формирования разных направлений и для разных возрастных групп. На сегодняшний день действуют </span>26<span> формирований различной жанровой направленности</span>, <span>в которых занимаются </span>409 человек<span>. </span></span><span>Популярны среди коллективы вокальной, танцевальной, театральной направленности. Они принимают участие в мероприятиях различного уровня. </span><span></span></p><p> </p>', NULL, 'sloboda.agov@yandex.ru', '[{"value": "78175542267"}]', '{"url": "https://all.culture.ru/uploads/2c6631eb3f986e654bfe8af3e0cc6a4d.jpg", "title": "слобод.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 77100, '[{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/95000pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/89989/slobodskoi-selskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=a130fd74-1b1b-48c0-84b2-b0470ced45ce&shareType=venue","serviceName":"ФанТам"}]', 77100, NULL, NULL, NULL, '2023-02-28 11:58:33+03', '2025-11-06 15:22:31+03', '0101000020E61000002C2AE274921D4440715AF0A2AF7A4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Фроловской сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'д 26', NULL, 'обл Вологодская,р-н Грязовецкий,д Фрол,д 26', '{"type": "Point", "coordinates": [40.491615, 58.921619]}', '<p>На базе Дома культуры осуществляют культурно-досуговую деятельность 11 клубных формирований, на которые </p><p>Для людей старшего возраста функционирует оздоровительный кружок «Вымпел», кружок декоративно-прикладного творчества «Фантазия», поэтический клуб «Вдохновение», вокальный ансамбль ветеранов «Забавушка».</p><p>Для детей и гостей учреждения проводятся интерактивные программы по сохранению народной традиционной культуры, а также разработана туристическая программ «Путешествие в старину».</p><p>В 2021 году был произведен ремонт входной группы, в 2022 году отремонтированы кровля, окна и двери.</p><p>Заведующий структурным подразделением Корпусова Валентина Александровна.</p>', NULL, 'frolovskoidk@yandex.ru', '[{"value": "78175545245"}]', '{"url": "https://all.culture.ru/uploads/24cc6ca1b2203fdb339d43bf5b0ee977.jpg", "title": "Фроловской  филиал (1) (1).jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 73718, '[{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/88518pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/86800/frolovskoi-selskii-dom-kultury","serviceName":"Культура.рф"}]', 73718, NULL, NULL, NULL, '2022-12-02 16:47:30+03', '2025-11-06 12:05:48+03', '0101000020E61000008D9C853DED3E4440A52F849CF7754D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Заемский сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'д 19', NULL, 'обл Вологодская,р-н Грязовецкий,д Заемье,д 19', '{"type": "Point", "coordinates": [40.29617991739845, 58.737811698092194]}', '<p>Заемский сельский дом культуры был основан в 1979 году. С тех пор является центром культурной жизни д. Заемье и близлежащих поселков.</p><p>В Заемском сельском доме культуры занимаются творчеством порядка 100 односельчан, посещая занятия 11 клубных формирований. Основные направления деятельности: вокал, хореография, театральное мастерство и декоративно-прикладное творчество.</p><p>Регулярно в Доме культуры проходят мастер-классы, праздничные программы, патриотические концерты, фестивали и конкурсы как для местных жителей, так и для гостей из близлежащих населенных пунктов.</p><p>Заведующая филиалом – Ольга Павловна Малеева.</p>', NULL, 'maleeva.69@inbox.ru', '[{"value": "79005066474", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/28567b996c89b30f4c4f264c0e46e60c.jpg", "title": "imgonline-com-ua-Resize-AUD7b49C7M.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 73687, '[{"url":"https://www.culture.ru/institutes/86766/zaemskii-selskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/89693pl","serviceName":"Афиша7"}]', 73687, NULL, NULL, NULL, '2022-12-02 12:53:06+03', '2025-11-06 12:01:02+03', '0101000020E6100000AA7A3939E9254440C3F41C9D705E4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Юровский сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'ул Центральная,д 1', NULL, 'обл Вологодская,р-н Грязовецкий,д Юрово,ул Центральная,д 1', '{"type": "Point", "coordinates": [39.986151, 58.969871]}', '<p>Юровский сельский Дом культуры является одним из филиалов бюджетного учреждения культуры Грязовецкого муниципального района Вологодской области «Культурно-досуговый центр» , территориально находится в Юровском муниципальном образовании.</p><p>Здание филиала построено в 1972 году.</p><p>Работа Юровского сельского Дома культуры делится на 7 направлений: хореография, вокал, экология, изобразительное искусство, спортивно-оздоровительное, исследовательно-познавательное и досуговое.</p><p>В филиале регулярно проводятся концерты, фестивали и конкурсы, участие в которых принимают не только жители Грязовецкого района, но и соседи из других областей.</p><p>Изменения в филиале происходят каждый год: в 2014 году был произведен ремонт кровли, в 2019 по нацпроекту «Культура» был произведен капитальный ремонт.</p><p>Ежегодно во благо посетителей укрепляется материально-техническая база филиала за счет привлечения средств местного и регионального бюджета.</p>', NULL, NULL, '[{"value": "79005332080"}]', '{"url": "https://all.culture.ru/uploads/a227a9873dc79038b3c3b5c1cc24b14c.jpg", "title": "ovCQHy3xuFY.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 72964, '[{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/87010pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/86075/yurovskii-selskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=ac1c22ea-2a97-4210-9e27-3a373f6807fe&shareType=venue","serviceName":"ФанТам"}]', 72964, NULL, NULL, NULL, '2022-11-18 15:27:53+03', '2025-11-05 18:00:29+03', '0101000020E610000077F52A323AFE43405E2BA1BB247C4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Сидоровский сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'ул Центральная,д 8', NULL, 'обл Вологодская,р-н Грязовецкий,д Сидоровское,ул Центральная,д 8', '{"type": "Point", "coordinates": [40.397508, 58.718253]}', '<p>Сидоровский сельский дом культуры является филиалом Культурно-досугового центра.</p><p>Здание учреждения введено в эксплуатацию в 1983, с тех пор является популярным местом встреч и отдыха не только для жителей деревни, но и близлежащих населенных пунктов.</p><p>Население д. Сидоровское занимается в клубных формированиях хорового пения, танцевальных, театральных кружках, студиях декоративно-прикладного творчества, вязания и вышивки лентами. Особой гордостью дома культуры является вокальный коллектив «Куделя», который принимает участие в районных, областных мероприятиях, концертах и фестивалях, а также является номинантом международной премии «Филантроп».</p><p>Осенью 2022 года в здании филиала произведен ремонт кровли, замена окон и дверей.</p>', NULL, NULL, '[{"value": "79005020178"}]', '{"url": "https://all.culture.ru/uploads/4f1836b68e7aa49784ad898bfd22fe8c.jpg", "title": "hUyHCvRCD0U.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 72960, '[{"url":"https://www.culture.ru/institutes/86063/sidorovskii-selskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/87905pl","serviceName":"Афиша7"}]', 72960, NULL, NULL, NULL, '2022-11-18 15:04:05+03', '2025-11-06 17:16:35+03', '0101000020E6100000FEF2C98AE13244407FA0DCB6EF5B4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Комьянский сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'ул Сосновая', NULL, 'обл Вологодская,р-н Грязовецкий,д Хорошево,ул Сосновая', '{"type": "Point", "coordinates": [40.27721429951374, 59.01996451016252]}', '<p>Здание структурного подразделения филиала Комьянского сельского дома культуры было введено в эксплуатацию в 1989 году и имеет достаточное количество отдельных помещений для культурно-досуговой работы.</p><p>В филиале осуществляют свою деятельность клубные формирования разных направлений, участниками которых являются 398 человек. Общее количество кружков и клубов – 24. Ведут работу 16 коллективов самодеятельного творчества: вокальные, танцевальные, декоративно-прикладного творчества, которые успешно и результативно принимают участие во многих фестивалях и конкурсах различного уровня. Здесь каждому найдется занятие по душе!</p>', NULL, NULL, '[{"value": "78175543257"}]', '{"url": "https://all.culture.ru/uploads/8ecd3db6f41af8d593edb49a7b7b7cce.jpg", "title": "3fzPw-AaHg8.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК Грязовецкого муниципального округа Вологодской области «Культурно-досуговый центр»', 'Грязовецкий район', 'Europe/Moscow', 'ул Карла Маркса,д 46', NULL, 'обл Вологодская,р-н Грязовецкий,г Грязовец,ул Карла Маркса,д 46', NULL, 3509010367, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Культурно-досуговый центр\"","networkId":"86530729","updateDate":"2021-06-24T12:11:18Z","createDate":"2021-06-24T12:11:18Z","accountId":38444,"postingGroupId":34915},{"network":"vk","name":"КиноГрязовец","networkId":"176595226","updateDate":"2023-05-03T08:03:55Z","createDate":"2023-05-03T08:03:55Z","accountId":38444,"postingGroupId":42088}]', 17441, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, NULL, '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 72955, '[{"url":"https://www.culture.ru/institutes/86053/komyanskii-selskii-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/86842pl","serviceName":"Афиша7"}]', 72955, NULL, NULL, NULL, '2022-11-18 14:44:11+03', '2025-11-06 12:00:42+03', '0101000020E6100000913217C27B234440451D73328E824D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Центр ремесел г. Вологды', 'Вологда', 'Europe/Moscow', 'ул Засодимского,д 5', NULL, 'обл Вологодская,г Вологда,ул Засодимского,д 5', '{"type": "Point", "coordinates": [39.87503, 59.225907]}', '<p>Центр ремесел был создан в 2020 году. Он является творческой площадкой для ремесленников, мастеров народных художественных промыслов и художников декоративно-прикладного искусства. Дом был построен в 1852 году и относится к памятникам деревянной архитектуры XIX века. </p> <p>За зданием находится уютный дворик с деревянным настилом для проведения мероприятий, красивый резной забор, кованые скамейки и эксклюзивные кресла ручной работы, разнообразные фотозоны. В учреждении проводятся конкурсы, мастер-классы, экскурсии, мероприятия, программы в сфере народных художественных промыслов в сотрудничестве с мастерами и ремесленниками Вологды и Вологодской области.</p>', 'https://centr-remesel35.ru', 'reznoi_palisad@mail.ru', '[{"value": "79535212968", "comment": "Менеджеры"}, {"value": "78172720485", "comment": "Менеджеры"}]', '{"url": "https://all.culture.ru/uploads/af913da54a4dd99377280b925a12319d.jpg", "title": "Дом 2.jpg"}', '[{"url": "https://all.culture.ru/uploads/3a397bd3256c03f673a3ac44f76973f2.jpg", "title": "0Fj0espyK-E.jpg"}, {"url": "https://all.culture.ru/uploads/f15bbf4cce5f491c22468da709e0d480.jpg", "title": "JaAoH3TbLfY.jpg"}, {"url": "https://all.culture.ru/uploads/9c27c2a420d7b37254a6834aa45f9b8c.jpg", "title": "726e2c9e373140738c3fa7727d2865d0.jpg"}, {"url": "https://all.culture.ru/uploads/3fdbc6aaa73466d13802adc59e1a0697.jpg", "title": "TWlHXfV3qw0.jpg"}, {"url": "https://all.culture.ru/uploads/b9af162fe664da780f04aff27f29eb79.jpg", "title": "ae5faf67a8721672f49ae703ae99121e.jpg"}, {"url": "https://all.culture.ru/uploads/54a8c89f21e86a60a03bcc27d906537b.jpg", "title": "ж.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МАУК «Центр ремесел»', 'Вологда', 'Europe/Moscow', 'ул Благовещенская,д 20', NULL, 'обл Вологодская,г Вологда,ул Благовещенская,д 20', NULL, 3525457970, 'mincult', 'Вологда', 'Europe/Moscow', NULL, 27656, '[{"id": 324, "name": "Традиционное искусство", "sysName": "tradicionnoe-iskusstvo"}, {"id": 206, "name": "Народное творчество", "sysName": "narodnoe-tvorchestvo"}, {"id": 329, "name": "Ремесла и художественные промыслы", "sysName": "remesla-i-hudozhestvennye-promysly"}]', NULL, '{"to": "19:00:00", "from": "08:30:00"}', '{"to": "19:00:00", "from": "08:30:00"}', '{"to": "19:00:00", "from": "08:30:00"}', '{"to": "19:00:00", "from": "08:30:00"}', '{"to": "19:00:00", "from": "08:30:00"}', '{"to": "19:00:00", "from": "10:00:00"}', '{"to": "19:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 65396, '[{"url":"https://www.culture.ru/institutes/100654/centr-remesel-g-vologdy","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vologda/prochee/71004pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=83639f57-582f-4516-ab6e-8e7e8c91b4df&shareType=venue","serviceName":"ФанТам"}]', 65396, NULL, NULL, NULL, '2022-03-16 14:52:05+03', '2025-11-05 11:11:02+03', '0101000020E61000006B82A8FB00F04340FF774485EA9C4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Центр народной культуры и художественных ремесел «Сокольский»', 'Сокольский район', 'Europe/Moscow', 'ул Советская,д 16', NULL, 'обл Вологодская,р-н Сокольский,г Сокол,ул Советская,д 16', '{"type": "Point", "coordinates": [40.13838, 59.45656]}', '<p>Центр народной культуры и художественных ремесел «Сокольский» начал свою работу в 1928 году. На сегодняшний день в учреждении работают 2 больших отдела: культурно-досуговый и художественных ремесел. </p><p>Большая работа проводится среди сокольчан всех возрастных категорий: календарные праздники, выпускные, вечера отдыха, концертные программы, торжественные и юбилейные вечера, ярмарки-продажи и выставки сувенирной продукции, изготовленной специалистами центра и реализуемой в Сокольском районе и за его пределами.</p><p>На базе учреждения работают 42 клубных формирования, из них 31 – на платной основе. Клубные формирования посещают 1 900 участников. В январе 2018 года «Сокольский» стал головным учреждением 5 сельских филиалов.</p>', NULL, 'cnk.sokol@mail.ru', '[{"value": "78173321563", "comment": "директор"}]', '{"url": "https://all.culture.ru/uploads/2e88533070c15b50a33dfa1400c610ee.jpg", "title": "L-S-1.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК СМО ЦНКИХР «Сокольский»', 'Сокольский район', 'Europe/Moscow', 'ул Советская,д 16', NULL, 'обл Вологодская,р-н Сокольский,г Сокол,ул Советская,д 16', NULL, 3527011797, 'mincult', 'Сокольский район', 'Europe/Moscow', NULL, 15137, '[{"id": 350, "name": "Народная культура", "sysName": "narodnaya-kultura"}, {"id": 329, "name": "Ремесла и художественные промыслы", "sysName": "remesla-i-hudozhestvennye-promysly"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "17:00:00", "from": "08:00:00"}', '{"to": "17:00:00", "from": "08:00:00"}', '{"to": "17:00:00", "from": "08:00:00"}', '{"to": "17:00:00", "from": "08:00:00"}', '{"to": "17:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 36397, '[{"url":"https://www.culture.ru/institutes/54401/centr-narodnoi-kultury-i-khudozhestvennykh-remesel-sokolskii","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/sokol/dvorcy-kultury-i-kluby/84299pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=abb1cfe2-5e8d-4698-bed9-073f4a290407&shareType=venue","serviceName":"ФанТам"}]', 36397, NULL, NULL, NULL, '2018-10-25 16:37:53+03', '2025-11-28 09:41:07+03', '0101000020E6100000D235936FB6114440B554DE8E70BA4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Культурный центр г. Устюжны', 'Устюженский район', 'Europe/Moscow', 'пер Богатырева,д 7', NULL, 'обл Вологодская,р-н Устюженский,г Устюжна,пер Богатырева,д 7', '{"type": "Point", "coordinates": [36.43383271984882, 58.84063621046935]}', '<p>Культурный центр был основан в 1968 году.</p><p>Сотрудники КЦ ведут деятельность по организации досуга местного населения, а также по развитию туризма и туристического обслуживания на территории Устюженского муниципального района. </p><p>В КЦ постоянно проводятся выставки, концерты, творческие вечера и праздники. </p> <p><span><span></span></span><span><span><span></span><span>На базе учреждения созданы и ведут работу творческие коллективы, объединения и клубы: </span></span></span></p><ul><li><span><span><span>танцевальный коллектив «Брусника» – младшая группа (4–5 лет), средняя группа (6–7 лет), средняя группа (8-12 лет), старшая группа (с 14 лет);</span></span></span></li><li><span><span><span>студия современного танца «Зумба»;</span></span></span></li><li><span><span><span>клуб здоровья «Легкая йога»;</span></span></span></li><li><span><span><span>народный академический хор ветеранов «Надежда»;</span></span></span></li><li><span><span><span>клуб ветеранов «Добрые сердца»;</span></span></span></li><li><span><span><span>творческое объединение «Альянс»;</span></span></span></li><li><span><span><span> <p>детская театральная студия «Дом солнца»;</p></span></span></span></li><li><span><span><span><p>театральная студия для взрослых «Так и надо»;</p></span></span></span></li><li><span><span><span><p> вокально-инструментальный ансамбль «Созвучие»;</p></span></span></span></li><li><span><span><span><p>коллектив русской песни ансамбль «Лад»;</p></span></span></span></li><li><span><span><span><p>ансамбль «Ровесники»;</p></span></span></span></li><li><span><span><span><p>танцевальный коллектив «Русская душа»;</p></span></span></span></li><li><span><span><span><p>мужской фольклорный ансамбль «Самогуды»;</p></span></span></span></li><li><span><span><span><p>инструментальный ансамбль «Мелодика»;</p></span></span></span></li><li><span><span><span><p>фольклорный ансамбль «Лествица»;</p></span></span></span></li><li><span><span><span><p> студия ведущих «Свит‘ОК».</p></span></span></span></li></ul>', 'http://us-omc.vlg.muzkult.ru/about', 'kultcenter-ust@yandex.ru', '[{"value": "79291223097", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/ea64066353e6425cd1e259cb1687d4c5.jpg", "title": "0vdHX53TJSU.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МУК «Устюженский организационно-методический центр культуры и туризма»', 'Устюженский район', 'Europe/Moscow', 'пер Богатырева,д 7', NULL, 'обл Вологодская,р-н Устюженский,г Устюжна,пер Богатырева,д 7', NULL, 3520007270, 'mincult', 'Устюженский район', 'Europe/Moscow', '[{"network":"vk","name":"КУЛЬТУРНЫЙ ЦЕНТР г.Устюжна","networkId":"168471357","updateDate":"2021-07-20T11:12:27Z","createDate":"2021-07-20T11:12:27Z","accountId":38491,"postingGroupId":35138}]', 16736, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 122, "name": "Искусство", "sysName": "iskusstvo"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "20:30:00", "from": "08:30:00"}', '{"to": "20:30:00", "from": "08:30:00"}', '{"to": "20:30:00", "from": "08:30:00"}', '{"to": "20:30:00", "from": "08:30:00"}', '{"to": "20:30:00", "from": "08:30:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 55550, '[{"url":"https://afisha7.ru/ustyuzhna/dvorcy-kultury-i-kluby/70679pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/78223/kulturnyi-centr-g-ustyuzhny","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=43894eb9-f389-429a-9d77-46da4d98e15a&shareType=venue","serviceName":"ФанТам"}]', 55550, NULL, NULL, NULL, '2021-07-09 17:35:08+03', '2026-01-27 10:04:32+03', '0101000020E6100000BCD79FD4873742404DE6A3F7996B4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Сидоровский сельский дом культуры', 'Грязовецкий район', 'Europe/Moscow', 'ул Школьная,д 3', NULL, 'обл Вологодская,р-н Грязовецкий,с Сидорово,ул Школьная,д 3', '{"type": "Point", "coordinates": [40.977361, 58.756881]}', '<p> Сидоровский Дом культуры с 1950 года – сердце культурной жизни села. С 2018 года учреждение расположено в просторном здании, зрительный зал рассчитан на 85 мест. Здесь кипит творческая жизнь: работают коллективы хореографии, вокала, художественного слова, проходят концерты, театрализованные представления, тематические вечера и праздники. Стенды Дома культуры украшают грамоты и дипломы, завоеванные на районных и областных конкурсах. Современная материально-техническая база – звукоусилительная аппаратура, световое оборудование, видеопроектор – обеспечивает высокое качество мероприятий. Сидоровский СДК – место, где каждый находит путь к самовыражению и становится частью дружной творческой семьи. </p>', 'https://vpdk.vlg.muzkult.ru/strukt', NULL, '[{"value": "78175561306"}]', '{"url": "https://all.culture.ru/uploads/360b598bc82e6d44d40c5133d38ffd8f.jpg", "title": "Сидоровский СДК Зрительный зал.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК «Вохтожский ПДК»', 'Грязовецкий район', 'Europe/Moscow', 'ул Юбилейная,д 23', NULL, 'обл Вологодская,р-н Грязовецкий,пгт Вохтога,ул Юбилейная,д 23', NULL, 3509007974, 'mincult', 'Грязовецкий район', 'Europe/Moscow', '[{"network":"vk","name":"БУК \"Вохтожский ПДК\"","networkId":"142709621","updateDate":"2023-06-03T06:04:17Z","createDate":"2023-06-03T06:04:17Z","accountId":44162,"postingGroupId":42507},{"network":"vk","name":"Ольга Фомичева","networkId":"146007613","updateDate":"2022-12-16T08:44:18Z","createDate":"2022-12-16T08:44:18Z","accountId":44162,"postingGroupId":38409},{"network":"vk","name":"Онлайн изостудия \"уDIVим\" БУК \"Вохтожский ПДК\"","networkId":"215937108","updateDate":"2022-12-16T08:44:44Z","createDate":"2022-12-16T08:44:44Z","accountId":44162,"postingGroupId":38410}]', 17457, NULL, NULL, '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 91543, '[{"url":"https://afisha7.ru/gryazovec/dvorcy-kultury-i-kluby/147068pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/104866/sidorovskii-selskii-dom-kultury","serviceName":"Культура.рф"}]', 91543, NULL, NULL, NULL, '2026-01-27 16:02:29+03', '2026-02-13 15:40:08+03', '0101000020E610000064B14D2A1A7D44405DFB027AE1604D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Сямженский центр культуры', 'Сямженский район', 'Europe/Moscow', 'ул Советская,д 10', NULL, 'обл Вологодская,р-н Сямженский,с Сямжа,ул Советская,д 10', '{"type": "Point", "coordinates": [41.076562, 60.019136]}', '<p>Датой своего рождения Сямженский центр культуры считает апрель 1962 года. Строительство здания было комсомольской стройкой. В ней принимали участие жители села, работали почти без техники. </p><p>Здание Центра культуры двухэтажное. Имеется зрительный зал на 180 мест, сцена, танцевальный зал для проведения массовых мероприятий, праздников, игровых программ для детей, вечеров отдыха для населения, ветеранов и молодежных дискотек. На втором этаже расположены кабинеты специалистов. </p><p>На базе учреждения работают 17 клубных формирований, которые посещают 303 участника: дети, молодежь, люди среднего возраста и ветераны.</p>', NULL, 'rsc_syamzha@mail.ru', '[{"value": "79815043684", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/01e26c4efcbb8424958d2cb37658b52f.jpg", "title": "q5PeDnrPJFI.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'Бюджетное учреждение культуры Сямженского МО «Сямженский Центр Культуры»', 'Сямженский район', 'Europe/Moscow', 'ул Советская,д 10', NULL, 'обл Вологодская,р-н Сямженский,с Сямжа,ул Советская,д 10', NULL, 3516003307, 'mincult', 'Сямженский район', 'Europe/Moscow', '[{"network":"vk","name":"БУК СМО \"Сямженский Центр Культуры\"","networkId":"26107541","updateDate":"2023-05-06T16:45:26Z","createDate":"2023-05-06T16:45:26Z","accountId":47494,"postingGroupId":42139}]', 17544, '[{"id": 323, "name": "Исполнительское искусство", "sysName": "ispolnitelskoe-iskusstvo"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 78301, '[{"url":"https://afisha7.ru/syamzha/dvorcy-kultury-i-kluby/98153pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/91144/syamzhenskii-centr-kultury","serviceName":"Культура.рф"}]', 78301, NULL, NULL, NULL, '2023-03-28 16:40:39+03', '2026-03-27 16:41:31+03', '0101000020E6100000E50E9BC8CC8944409016670C73024E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Сазоновский дом культуры', 'Чагодощенский район', 'Europe/Moscow', 'ул Советская,д 14', NULL, 'обл Вологодская,р-н Чагодощенский,рп Сазоново,ул Советская,д 14', '{"type": "Point", "coordinates": [35.231961, 59.083805]}', '<p style="margin-left:0px">На базе Сазоновского Дома культуры ведут деятельность клубные формирования для детей, молодежи и взрослого населения по различным направлениям. </p> <p style="margin-left:0px">Работают кружки: студия эстрадного вокала, танцевальные, театральные, музыкальная студия «Лаборатория», клуб «Золотой возраст», интеллектуальный клуб знатоков, семейная студия «В кругу друзей», юношеский интеллектуальный клуб «Эрудит», фитнес-студия. Творческие коллективы Дома культуры неоднократно становились победителями и лауреатами различных международных фестивалей. В доме культуры проводятся мероприятия, посвященные праздничным и памятным датам, игровые и танцевальные программы.</p>', 'https://sazonovodk.ru', 'sazonovodk@mail.ru', '[{"value": "78174131338", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/6f907d53b367dd2f0b7c5ce444a2c99e.jpg", "title": "дк.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУ Сазоновский ДК', 'Чагодощенский район', 'Europe/Moscow', 'ул Советская,д 14', NULL, 'обл Вологодская,р-н Чагодощенский,рп Сазоново,ул Советская,д 14', NULL, 3522001241, 'mincult', 'Чагодощенский район', 'Europe/Moscow', NULL, 39609, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 92629, '[{"url":"https://www.culture.ru/institutes/105913/sazonovskii-dom-kultury","serviceName":"Культура.рф"}]', 92629, NULL, NULL, NULL, '2026-04-08 08:32:03+03', '2026-04-10 14:09:00+03', '0101000020E61000004679E6E5B09D4140E21E4B1FBA8A4D40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Сусоловский клуб', 'Великоустюгский район', 'Europe/Moscow', 'ул Рабочая,д 13', 'В настоящий момент ведется капитальный ремонт здания', 'обл Вологодская,р-н Великоустюгский,п Сусоловка,ул Рабочая,д 13', '{"type": "Point", "coordinates": [47.040208, 60.819204]}', '<p>Главное направление работы – это сохранение традиций и организация досуга всех возрастных категорий, развитие и сохранение культурного наследия России. </p><p>В клубе организована кружковая работа – кружок «Очумелые ручки», ансамбль «Сусоловские девчата» и группа «Калина». Кружковцы активно принимают участие в концертах, различных благотворительных мероприятиях, в районных фестивалях.<br>Сусоловским клубом ведется спортивно-оздоровительная деятельность – организована группа здоровья «Финская ходьба», проводятся памятные мероприятия, посвященные 9 Мая, вечера отдыха, выставки, викторины, концертные программы к различным праздникам. Во время каникул и праздничных дат проходят детские игровые программы, спортивные мероприятия и дискотеки.<br>Сусоловский клуб сотрудничает с общественными организациями поселка: Женсоветом и Советом Ветеранов, участвует в мероприятиях благоустройству малой родины. Сейчас клубом руководит – Усова Ольга Альбертовна.</p>', 'http://кдцву.рф/', '89115153037@yandex.ru', '[{"value": "79115153037", "comment": "начальник обособленного подразделения Усова Ольга Альбертовна"}, {"value": "78173826684", "comment": "менеджер по работе с сельскими клубами - Жирохова Наталья Викторовна"}]', '{"url": "https://all.culture.ru/uploads/818e18d4036db161c839a37c94ffa7bf.jpg", "title": "QD9lXx7w_Wsg5cJfs-N5cbaSlmGl9xlBIHs-JZbZysNXJipHGMZoH7dws2ORp3n6Edbj5WAjynOBD_zpir1spiAy.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11:45:45Z","accountId":46589,"postingGroupId":41531},{"network":"vk","name":"\"Усть-Алексеевский клуб\"","networkId":"196143083","updateDate":"2023-04-05T13:11:25Z","createDate":"2023-04-05T13:11:25Z","accountId":46589,"postingGroupId":41534},{"network":"vk","name":"«Верхневарженский клуб»","networkId":"219499380","updateDate":"2023-04-05T11:45:28Z","createDate":"2023-04-05T11:45:28Z","accountId":46589,"postingGroupId":41530},{"network":"vk","name":"«Морозовский клуб»","networkId":"219948363","updateDate":"2023-07-05T08:23:07Z","createDate":"2023-07-05T08:23:07Z","accountId":46589,"postingGroupId":42638},{"network":"vk","name":"«Новаторский клуб»","networkId":"217628593","updateDate":"2023-03-17T08:05:55Z","createDate":"2023-03-17T08:05:55Z","accountId":46589,"postingGroupId":41030},{"network":"vk","name":"Анюта Красникова","networkId":"17613040","updateDate":"2023-03-17T10:43:29Z","createDate":"2023-03-17T10:43:29Z","accountId":46594,"postingGroupId":41037},{"network":"vk","name":"БУК \"Юдинский дом культуры\" п. Стрига 6а","networkId":"160210512","updateDate":"2023-04-11T12:03:48Z","createDate":"2023-04-11T12:03:48Z","accountId":46589,"postingGroupId":41660},{"network":"vk","name":"Великоустюгский культурно-досуговый центр","networkId":"117993849","updateDate":"2024-02-15T08:49:55Z","createDate":"2024-02-15T08:49:55Z","accountId":46589,"postingGroupId":44737},{"network":"vk","name":"Обособленное подразделение \"Аристовский клуб\"","networkId":"195948369","updateDate":"2023-03-17T08:06:12Z","createDate":"2023-03-17T08:06:12Z","accountId":46589,"postingGroupId":41031},{"network":"vk","name":"Обособленное подразделение \"Сусоловский клуб\"","networkId":"219106681","updateDate":"2023-04-07T11:43:09Z","createDate":"2023-04-07T11:43:09Z","accountId":46589,"postingGroupId":41581},{"network":"vk","na