INSERT INTO culture_data.culture_palaces_clubs VALUES ('Покровский клуб', 'Великоустюгский район', 'Europe/Moscow', 'д 22', 'в летний период – паром из г. Великий Устюг; в зимний период – по ледовой переправе, расположенной на 680-м км реки Северная Двина)', 'обл Вологодская,р-н Великоустюгский,д Чучеры,д 22', '{"type": "Point", "coordinates": [46.606843, 60.641687]}', '<p>Покровский Дом культуры находится на территории д. Покрово. Здание не типовое. </p><p>В Доме культуры проводились концерты по всем календарным датам. Проводы в армию, свадьбы, посиделки, вечера отдыха. Проводила праздники деревень по всем маленьким деревням, праздник колодца в д. Новоселово. </p><p>Работали кружки: художественной самодеятельности, бильярдный, шахматный, шашечный, вязанье, лоскутное шитье. </p><p>Сейчас при Доме культуры ансамбль «Покровляночки» в составе пяти человек. Участвуют в городских фестивалях и на территории поселения. По приглашению осуществляют выездные концерты в другие дома культуры . </p>', 'http://кдцву.рф', 'galochkamedvedchikova@yandex.ru', '[{"value": "79211414716", "comment": "Заведующий Медведчикова Галина Геннадьевна"}, {"value": "78173865432", "comment": "Начальник Соболева Людмила Владимировна"}]', '{"url": "https://all.culture.ru/uploads/bf5b8a41c7167ee03b6afc803dbdabe6.jpg", "title": "AofUtIh8SRg.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11:45:45Z","accountId":46589,"postingGroupId":41531},{"network":"vk","name":"\"Усть-Алексеевский клуб\"","networkId":"196143083","updateDate":"2023-04-05T13:11:25Z","createDate":"2023-04-05T13:11:25Z","accountId":46589,"po