e":"Парк культуры и отдыха /Великий Устюг/","networkId":"153198570","updateDate":"2023-04-05T11:46:08Z","createDate":"2023-04-05T11:46:08Z","accountId":46589,"postingGroupId":41532},{"network":"vk","name":"Полдарский клуб","networkId":"206228726","updateDate":"2023-07-05T08:23:33Z","createDate":"2023-07-05T08:23:33Z","accountId":46589,"postingGroupId":42639},{"network":"vk","name":"Театр Деда Мороза","networkId":"199304892","updateDate":"2020-11-03T05:54:59Z","createDate":"2020-11-03T05:54:59Z","accountId":21245,"postingGroupId":30273}]', 20409, '[{"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "12:00:00", "from": "10:00:00"}', '{"to": "12:00:00", "from": "10:00:00"}', '{"to": "12:00:00", "from": "10:00:00"}', '{"to": "12:00:00", "from": "10:00:00"}', '{"to": "12:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 82079, '[{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/108025pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/95058/pokrovskii-klub","serviceName":"Культура.рф"}]', 82079, NULL, NULL, NULL, '2023-12-07 11:16:27+03', '2026-04-09 17:03:24+03', '0101000020E61000003C670B08AD4D474059A2B3CC22524E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Палемский клуб', 'Великоустюгский район', 'Europe/Moscow', 'д 51', 'в летний период – паром из г. Великий Устюг; в зимний период – по ледовой переправе', 'обл Вологодская,р-н Великоустюгский,д Измарухово,д 51', '{"type": "Point", "coordinates": [46.868809, 60.644409]}', '<p> Палемский сельский клуб начал свое существование в 1951 году. Здесь организовывают досуг для сельчан, развивают творческие способности и открывают новые таланты. </p><p> Для детей ведется кружковая работа: «Лоскутное шитье», «Макраме» (руководитель – Галина Николаевна Бебякина) «Поделки своими руками», «Настольные игры». Действуют два любительских объединения: «Лоскутная мозаика» (4 человека) и «Художественная самодеятельность» (6 человек).</p><p> В летний период и на каникулах школьники с удовольствием посещают мероприятия в Доме культуры: викторины, детские дискотеки, игры на свежем воздухе и у реки. </p><p>Для жителей проводятся тематические вечера, праздничные вечера отдыха, отчетно-выборные собрания, культурно-массовые мероприятия, торжественные митинги, молодежные дискотеки, юбилейные вечера отдыха и день деревни. Уютный зал всегда с радостью принимает зрителей, приходящих на праздники.</p><p> </p>', 'http://кдцву.рф', 'warya68@mail.ru', '[{"value": "78173820833", "comment": "Заведующая Воронина Елена Юрьевна"}, {"value": "78173865432", "comment": "Начальник Соболева Людмила Владимировна"}]', '{"url": "https://all.culture.ru/uploads/79a9c452f5772b0d5221c1839ea7fd60.JPG", "title": "IMG_3134.JPG"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11