INSERT INTO culture_data.culture_palaces_clubs VALUES ('Юдинский клуб', 'Великоустюгский район', 'Europe/Moscow', 'д 6А', 'авт. № 125', 'обл Вологодская,р-н Великоустюгский,п Стрига,д 6А', '{"type": "Point", "coordinates": [46.33712918650815, 60.79727357750445]}', '<p>Юдинский дом культуры был построен в 1968 г. и находился в д. Аксеново. Должность заведующей занимала Павлова Эмилия Ивановна. Здесь проводились многочисленные мероприятия: концерты, выездные мероприятия агитбригады на фермы и поля, субботники, творческие отчеты. В 1988 г. клуб перевезли в п. Стрига.</p><p>Для населения работают клубные формирования:</p><ol><li> «ОчУмелые ручки».</li><li>Танцевальный кружок.</li><li>«Звонкий колокольчик».</li><li>«Теннис».</li><li>«Юдинские девчата».</li><li>«Здоровье».</li><li>«Волшебная петелька».</li><li>«Лоскутное шитье».</li><li>«Рукодельница».</li><li>«Самбо».</li><li>«Чудеса своими руками» (в д. Будрино).</li></ol><p> Общее количество участников – 90 человек. </p><p> Все коллективы и исполнители – постоянные участники районных праздников и фестивалей. </p><p>С 2019 г. клуб постоянно участвует в программе «Народный бюджет». Для качественного проведения мероприятий в 2019 г. были приобретены ноутбук, проектор, аудиосистема. В 2020 г. для ансамбля «Юдинские девчата» сшили сценические костюмы. В 2021 г. в здании были установлены окна ПВХ. Приобрели швейные машины для кружка «Рукодельницы». В 2022 г. были закуплены столы для кройки и шитья. Вставили входную металлическую дверь, а также приобрели борцовский ковер для занятия спортом. </p><p>В настоящее время всю работу по организации досуга населения Юдинского поселения осуществляют 3 специалиста. <br></p><p> </p>', 'http://кдцву.рф', 'strigaclyb@rambler.ru', '[{"value": "78173863546", "comment": "начальник подразделения Валерия Алексеевна Старостина"}, {"value": "78173865837", "comment": "менеджер Наталья Викторовна Жирохова"}]', '{"url": "https://all.culture.ru/uploads/9ef1776e34c3208b75509a10745c2e2e.jpg", "title": "SYI0P5Kw9uE.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11:45:45Z","accountId":46589,"postingGroupId":41531},{"network":"vk","name":"\"Усть-Алексеевский клуб\"","networkId":"196143083","updateDate":"2023-04-05T13:11:25Z","createDate":"2023-04-05T13:11:25Z","accountId":46589,"postingGroupId":41534},{"network":"vk","name":"«Верхневарженский клуб»","networkId":"219499380","updateDate":"2023-04-05T11:45:28Z","createDate":"2023-04-05T11:45:28Z","accountId":46589,"postingGroupId":41530},{"network":"vk","name":"«Морозовский клуб»","networkId":"219948363","updateDate":"2023-07-05T08:23:07Z","createDate":"2023-07-05T08:23:07Z","accountId":46589,"postingGroupId":42638},{"network":"vk","name":"«Новаторский клуб»","networkId":"217628593","updateDate":"2023-03-17T08:05:55Z","createDate":"2023-03-17T08:05:55Z","accountId":46589,"postingGroupId":41030},{"network":"vk","name":"Анюта Красникова","networkId":"17613040","updateDate":"2023-03-17T10:43:29Z","createDate":"2023-03-17T10:43:29Z","accountId":46594,"postingGroupId":41037},{"network":"vk","name":"БУК \"Юдинский дом культуры\" п. Стрига 6а","networkId":"160210512","updateDate":"2023-04-11T12:03:48Z","createDate":"2023-04-11T12:03:48Z","accountId":46589,"postingGroupId":41660},{"network":"vk","name":"Великоустюгский культурно-досуговый центр","networkId":"117993849","updateDate":"2024-02-15T08:49:55Z","createDate":"2024-02-15T08:49:55Z","accountId":46589,"postingGroupId":44737},{"network":"vk","name":"Обособленное подразделение \"Аристовский клуб\"","networkId":"195948369","updateDate":"2023-03-17T08:06:12Z","createDate":"2023-03-17T08:06:12Z","accountId":46589,"postingGroupId":41031},{"network":"vk","name":"Обособленное подразделение \"Сусоловский клуб\"","networkId":"219106681","updateDate":"2023-04-07T11:43:09Z","createDate":"2023-04-07T11:43:09Z","accountId":46589,"postingGroupId":41581},{"network":"vk","name":"Обособленное подразделение \"Теплогорский клуб\"","networkId":"97047864","updateDate":"2023-04-07T11:43:26Z","createDate":"2023-04-07T11:43:26Z","accountId":46589,"postingGroupId":41582},{"network":"vk","name":"Окультурено молодежью","networkId":"199241624","updateDate":"2023-03-17T10:42:43Z","createDate":"2023-03-17T10:42:43Z","accountId":46594,"postingGroupId":41036},{"network":"vk","name":"Парк культуры и отдыха /Великий Устюг/","networkId":"153198570","updateDate":"2023-04-05T11:46:08Z","createDate":"2023-04-05T11:46:08Z","accountId":46589,"postingGroupId":41532},{"network":"vk","name":"Полдарский клуб","networkId":"206228726","updateDate":"2023-07-05T08:23:33Z","createDate":"2023-07-05T08:23:33Z","accountId":46589,"postingGroupId":42639},{"network":"vk","name":"Театр Деда Мороза","networkId":"199304892","updateDate":"2020-11-03T05:54:59Z","createDate":"2020-11-03T05:54:59Z","accountId":21245,"postingGroupId":30273}]', 20409, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', '[{"hosting":"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-160210512&id=456239065&hash=948c8be9a3bdecfb&hd=2\" width=\"853\" height=\"480\"></iframe>"},{"hosting":"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-160210512&id=456239063&hash=aad16893273245fb&hd=2\" width=\"853\" height=\"480\"></iframe>"},{"hosting":"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-160210512&id=456239063&hash=aad16893273245fb&hd=2\" width=\"853\" height=\"480\"></iframe>"}]', NULL, '{"to": "17:30:00", "from": "12:00:00"}', '{"to": "17:30:00", "from": "12:00:00"}', '{"to": "17:30:00", "from": "12:00:00"}', '{"to": "17:30:00", "from": "12:00:00"}', '{"to": "15:00:00", "from": "10:00:00"}', '{"to": "15:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 79008, '[{"url":"https://www.culture.ru/institutes/91855/yudinskii-klub","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/99465pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=30e8f778-5d79-441c-9f7b-5ca9a21b163c&shareType=venue","serviceName":"ФанТам"}]', 79008, NULL, NULL, NULL, '2023-04-13 15:32:54+03', '2026-04-24 16:11:38+03', '0101000020E6100000304A970C272B47405BAC820F0D664E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Кузинский клуб', 'Великоустюгский район', 'Europe/Moscow', 'ул Лермонтова,д 12', 'в летний период – паром из г. Великий Устюг; в зимний период – по ледовой переправе, расположенной на 680-м км реки Северная Двина', 'обл Вологодская,р-н Великоустюгский,рп Кузино,ул Лермонтова,д 12', '{"type": "Point", "coordinates": [46.372688, 60.732906]}', '<p>В архивных фондах первое упоминание о Кузинском доме культуры относится к 20 ноября 1919 году. </p> <p>Дом культуры предоставляет широкий спектр услуг: концертные, конкурсные, развлекательные, игровые, познавательные программы, литературно-музыкальные, тематические и танцевальные вечера-встречи, детские и молодежные дискотеки, конкурсные выставки.</p> <p><span> <span></span><span></span></span><span></span></p> <p><span>На базе учреждения работают 9 клубных формирований:</span></p><ol><li><span>Для детей: танцевальный коллектив «Нежность», вокальный коллектив «Юность», танцевальный фитнес «Зумба», кружок декоративно-прикладного искусства «Очумелые ручки», кружок «Веселая карусель». </span></li><li><span>Для взрослых: ансамбль «Лейся, песня», клуб «Хозяюшки», «Кузинские девчата», вокальный коллектив «От души, с любовью». </span></li></ol><p><span>Возраст участников клубных формирований – от 8 до 75 лет, на бесплатной основе занимается 131 человек.</span></p><p><span></span><span>Коллективы художественной самодеятельности участвуют в</span><span> </span><span>районных и</span><span> </span><span>межрегиональных конкурсах, фестивалях и я</span><span>вляются победителями, лауреатами многих конкурсов.</span></p><p><span> Ежегодно проводятся праздники: День защитника Отечества, Международный женский день, День Победы, День защиты детей, День России, День поселка, День пожилого человека, День народного единства, День матери, новогодние праздники и многие другие.</span></p><p><span>Традиционным праздником стал день Иван Купалы «Костры купальской ночи»: в начале июля на берег реки приходят не только жители близлежащих населенных пунктов, но и туристы из других городов.</span></p>', 'http://кдцву.рф', 'dkkuzino@mail.ru', '[{"value": "79535220483", "comment": "Директор Соколова Татьяна Анатольевна"}, {"value": "79814247579", "comment": "Художественный руководитель Маркова Елена Руслановна"}]', '{"url": "https://all.culture.ru/uploads/fc0eda03eafd673b32387bbdeea3fad4.jpg", "title": "Вход для посетителей.jpg"}', '[{"url": "https://all.culture.ru/uploads/39e64caa54b642b369b21954e41ccecd.jpg", "title": "nj9hcLS5ZEI.jpg"}, {"url": "https://all.culture.ru/uploads/cf31f6de40486252879bc73160333dfb.jpg", "title": "hDiFBmQEskM.jpg"}, {"url": "https://all.culture.ru/uploads/8eda53459846ba16b2b9319d91ee3a26.jpg", "title": "2.jpg"}, {"url": "https://all.culture.ru/uploads/79e0e57060b0cc98298403d2fa210c94.jpg", "title": "3.jpg"}, {"url": "https://all.culture.ru/uploads/ccfea7e161bdb131c4ed4f81fe224323.jpg", "title": "q-Nn7HrbHbE.jpg"}, {"url": "https://all.culture.ru/uploads/b9ec202e1807ee9b5b7184d8835b09a6.jpg", "title": "CbZ-DZMC3og.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11:45:45Z","accountId":46589,"postingGroupId":41531},{"network":"vk","name":"\"Усть-Алексеевский клуб\"","networkId":"196143083","updateDate":"2023-04-05T13:11:25Z","createDate":"2023-04-05T13:11:25Z","accountId":46589,"postingGroupId":41534},{"network":"vk","name":"«Верхневарженский клуб»","networkId":"219499380","updateDate":"2023-04-05T11:45:28Z","createDate":"2023-04-05T11:45:28Z","accountId":46589,"postingGroupId":41530},{"network":"vk","name":"«Морозовский клуб»","networkId":"219948