T08:23:33Z","createDate":"2023-07-05T08:23:33Z","accountId":46589,"postingGroupId":42639},{"network":"vk","name":"Театр Деда Мороза","networkId":"199304892","updateDate":"2020-11-03T05:54:59Z","createDate":"2020-11-03T05:54:59Z","accountId":21245,"postingGroupId":30273}]', 20409, '[{"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 751, "name": "Культура для школьников", "sysName": "kultura-dlya-shkolnikov"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, NULL, '{"to": "19:00:00", "from": "11:00:00"}', '{"to": "19:00:00", "from": "11:00:00"}', '{"to": "19:00:00", "from": "11:00:00"}', '{"to": "19:00:00", "from": "11:00:00"}', '{"to": "16:00:00", "from": "12:00:00"}', '{"to": "16:00:00", "from": "12:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 78764, '[{"url":"https://www.culture.ru/institutes/91605/kuzinskii-klub","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/99111pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=4dce7f0e-892d-400c-a35d-ca82d90911b5&shareType=venue","serviceName":"ФанТам"}]', 78764, NULL, NULL, NULL, '2023-04-07 11:25:11+03', '2026-04-29 16:47:22+03', '0101000020E61000004ACE893DB42F4740668522DDCF5D4E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Полдарский клуб', 'Великоустюгский район', 'Europe/Moscow', 'ул Центральная,д 1', 'автобус от автовокзала Великого Устюга по расписанию', 'обл Вологодская,р-н Великоустюгский,п Полдарса,ул Центральная,д 1', '{"type": "Point", "coordinates": [45.398654, 60.595198]}', '<p>В 1955 году Полдарский клуб впервые распахнул свои двери для жителей поселка. На тот период деятельность клуба заключалась в кинопоказах художественных фильмов. Здание было деревянное, лишь в 80-х годах его усилили кирпичом. В 1997 году клуб был передан отделу культуры и получил статус «Дом культуры». </p><p>Деятельность учреждения направлена на сохранение и развитие самодеятельного художественного творчества, в том числе организацию деятельности коллективов и досуга населения с учетом различных возрастных категорий. Клуб проводит различные мероприятия: концертные, конкурсно-развлекательные, литературно-музыкальные, тематические вечера, фестивали и смотры.</p><p><a href="http://xn--b1adr2bn.xn--p1ai/_si/0/16841406.jpg" target="_blank"></a></p><p>На базе клуба занимаются вокальные коллективы «Гармония», «Вдохновение», «Кичужаночки». Для молодежи функционирует спортивный клуб по интересам «Настольный теннис», а для людей старшего возраста – клубы по интересам «Здоровье», «Творческая мастерская», «Рукодельница», спортивный. Дети могут проявить себя на занятиях кружка «Умелые ручки».</p>', 'http://кдцву.рф', 'kultura.dom2013@yandex.ru', '[{"value": "79114487200", "comment": "начальник обособленного подразделения Мустяцэ Наталья Владимировна"}, {"value": "78173865837", "comment": "менеджер Жирохова Наталья Викторовна"}]', '{"url": "https://all.culture.ru/uploads/f7dff4f71ae692b49f0e6ef12be69ebc.jpg", "title": "6g15Drmeryc.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11:45:45Z","accountId":46589,"postingGroupId":41531},{"network":"vk","name":"\"Усть-Алексеевский клуб\"","networkId":"196143083","updateDate":"2023-04-05T13:11:25Z","createDate":"2023-04-05T13:11:25Z","accountId":46589,"postingGroupId":41534},{"network":"vk","name":"«Верхневарженский клуб»","networkId":"219499380","updateDate":"2023-04-05T11:45:28Z","createDate":"2023-04-05T11:45:28Z","accountId":46589,"postingGroupId":41530},{"network":"vk","name":"«Морозовский клуб»","networkId":"219948363","updateDate":"2023-07-05T08:23:07Z","createDate":"2023-07-05T08:23:07Z","accountId":46589,"postingGroupId":42638},{"network":"vk","name":"«Новаторский клуб»","networkId":"217628593","updateDate":"2023-03-17T08:05:55Z","createDate":"2023-03-17T08:05:55Z","accountId":46589,"postingGroupId":41030},{"network":"vk","name":"Анюта Красникова","networkId":"17613040","updateDate":"2023-03-17T10:43:29Z","createDate":"2023-03-17T10:43:29Z","accountId":46594,"postingGroupId":41037},{"network":"vk","name":"БУК \"Юдинский дом культуры\" п. Стрига 6а","networkId":"160210512","updateDate":"2023-04-11T12:03:48Z","createDate":"2023-04-11T12:03:48Z","accountId":46589,"postingGroupId":41660},{"network":"vk","name":"Великоустюгский культурно-досуговый центр","networkId":"117993849","updateDate":"2024-02-15T08:49:55Z","createDate":"2024-02-15T08:49:55Z","accountId":46589,"postingGroupId":44737},{"network":"vk","name":"Обособленное подразделение \"Аристовский клуб\"","networkId":"195948369","updateDate":"2023-03-17T08:06:12Z","createDate":"2023-03-17T08:06:12Z","accountId":46589,"postingGroupId":41031},{"network":"vk","name":"Обособленное подразделение \"Сусоловский клуб\"","networkId":"219106681","updateDate":"2023-04-07T11:43:09Z","createDate":"2023-04-07T11:43:09Z","accountId":46589