:00:00"}', '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "22:00:00", "from": "20:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 78271, '[{"url":"https://www.culture.ru/institutes/91128/ust-alekseevskii-klub","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/99094pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=c6799139-d026-4cb8-b436-9a825087ba26&shareType=venue","serviceName":"ФанТам"}]', 78271, NULL, NULL, NULL, '2023-03-28 11:31:41+03', '2026-04-24 16:11:53+03', '0101000020E6100000EC681CEA773F4740753FA7203F3B4E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Морозовский клуб', 'Великоустюгский район', 'Europe/Moscow', 'ул Набережная,д 21', NULL, 'обл Вологодская,р-н Великоустюгский,д Морозовица,ул Набережная,д 21', '{"type": "Point", "coordinates": [46.29770446626046, 60.708649864083824]}', '<p>Морозовский клуб был основан в 1973 году. Основные направления работы – патриотическое, краеведческое, пропаганда здорового образа жизни, организация досуга всех категорий населения. </p><p>При учреждении действуют клубные формирования по различным направлениям (народное творчество, вокальное и хореографическое направления, прикладное творчество, спорт, клубы по интересам): </p><ul><li>ансамбль русской песни «Завалинка»;</li><li>вокальная группа «Апрель»;</li><li>детский вокальный коллектив «Конфетти»;</li><li>детский танцевальный коллектив «Карамельки»;</li><li>танцевальный коллектив «Задоринки»;</li><li>семейный клуб «Счастливы вместе»;</li><li>женский клуб «Хорошее настроение»;</li><li>спортивная секция по джампингу.<br></li></ul><p>На базе клуба проходят районные праздники, фестивали, конкурсы. Коллективы художественной самодеятельности участвуют в районных и межрегиональных конкурсах, фестивалях, часто становятся победителями и лауреатами конкурсов. </p>', 'http://кдцву.рф', 'mbykmorozovskoesk@mail.ru', '[{"value": "79218202148", "comment": "начальник ОП Лобанова Лидия Васильевна"}, {"value": "78173826684", "comment": "менеджер Наталья Викторовна Жирохова"}]', '{"url": "https://all.culture.ru/uploads/9faa0881c11fa5206cf19ba9f9a7c107.jpg", "title": "ajwRcMhe783wRJ-iv-D5HLIHHYFzRoJsLvBY5Wp30rQeKMvxJ22yqxTlVYDBOc5cZavP82g4xelBq1Kv8hcmCZJm.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","n