NULL, '2022-06-24 21:22:22+03', '2026-04-29 15:51:12+03', '0101000020E61000001D3B112E1B2647400647EB09B55A4E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Верхневарженский клуб', 'Великоустюгский район', 'Europe/Moscow', 'д 75', 'автобус от автовокзала г. Великого Устюга', 'обл Вологодская,р-н Великоустюгский,д Мякинницыно,д 75', '{"type": "Point", "coordinates": [46.641958, 60.337812]}', '<p>Первый сельский клуб в поселении появился в 1954 году. В 1967 году по инициативе директора совхоза «Пионер» Карачева Алексея Александровича начали строительство нового здания для клуба. Оно было введено в эксплуатацию осенью 1971 года. В клубе был зал на 120 мест и бильярд. Каждый день проводились киносеансы. Часто приезжали с концертами артисты из Вологды. Выступала и знаменитая певица О. Воронец. </p><p>В 1987 году лауреатами II Всесоюзного фестиваля народного творчества РСФСР стали А. В. Баева, Г. С. Васильева, Е. П. Ворошнина, Т. Р. Доровицына, А. Б. Жерихин, В. Н. Жерихина, Г. Н. Осиева, И. Ф. Третьякова. </p><p>С 2000 года клуб совместно с библиотекой начал проводить дни покинутых и жилых деревень. С концертной программой в эти населенные пункты выезжают творческие коллективы клуба, а также приглашаются коллективы из Устюга. </p><p>Ежегодно клуб участвует в Прокопьевской ярмарке в Великом Устюге и не раз занимал призовые места. Ежегодно проводятся выставки изделий, сделанных руками местных жителей. В клубе проходят вечера, посвященные чествованию юбиляров. </p>', 'http://кдцву.рф', 'verxnewarjensckij@yandex.ru', '[{"value": "79814259086", "comment": "начальник обособленного подразделения Сакулина Татьяна Валентиновна"}, {"value": "78173865837", "comment": "менеджер Жирохова Наталья Викторовна"}]', '{"url": "https://all.culture.ru/uploads/3146ce8e774ccb6b163d7ce601bd216a.jpeg", "title": "ДК.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11:45:45Z","accountId":46589,"postingGroupId":41531},{"network":"vk","name":"\"Усть-Алексеевский клуб\"","networkId":"196143083","updateDate":"2023-04-05T13:11:25Z","createDate":"2023-04-05T13:11:25Z","accountId":46589,"postingGroupId":41534},{"network":"vk","name":"«Верхневарженский клуб»","networkId":"219499380","updateDate":"2023-04-05T11:45:28Z","createDate":"2023-04-05T11:45:28Z","accountId":46589,"postingGroupId":41530},{"network":"vk","name":"«Морозовский клуб»","networkId":"219948363","updateDate":"2023-07-05T08:23:07Z","createDate":"2023-07-05T08:23:07Z","accountId":46589,"postingGroupId":42638},{"network":"vk","name":"«Новаторский клуб»","networkId":"217628593","updateDate":"2023-03-17T08:05:55Z","createDate":"2023-03-17T08:05:55Z","accountId":46589,"postingGroupId":41030},{"network":"vk","name":"Анюта Красникова","networkId":"17613040","updateDate":"2023-03-17T10:43:29Z","createDate":"2023-03-17T10:43:29Z","accountId":46594,"postingGroupId":41037},{"network":"vk","name":"БУК \"Юдинский дом культуры\" п. Стрига 6а","networkId":"160210512","updateDate":"2023-04-11T12:03:48Z","createDate":"2023-04-11T12:03:48Z","accountId":46589,"postingGroupId":41660},{"network":"vk","name":"Великоустюгский культурно-досуговый центр","networkId":"117993849","updateDate":"2024-02-15T08:49:55Z","createDate":"2024-02-15T08:49:55Z","accountId":46589,"postingGroupId":44737},{"network":"vk","name":"Обособленное подразделение \"Аристовский клуб\"","networkId":"195948369","updateDate":"2023-03-17T08:06:12Z","createDate":"2023-03-17T08:06:12Z","accountId":46589,"postingGroupId":41031},{"network":"vk","name":"Обособленное подразделение \"Сусоловский клуб\"","networkId":"219106681","updateDate":"2023-04-07T11:43:09Z","createDate":"2023-04-07T11:43:09Z","accountId":46589,"postingGroupId":41581},{"network":"vk","name":"Обо