INSERT INTO culture_data.culture_palaces_clubs VALUES ('Орловский клуб', 'Великоустюгский район', 'Europe/Moscow', 'д 100', NULL, 'обл Вологодская,р-н Великоустюгский,д Чернево,д 100', '{"type": "Point", "coordinates": [46.635535, 60.500312]}', '<p>Первый клуб в деревне Орлово появился в 1950 году. Он находился в отдельном приспособленном доме. Заведующим был С. И. Мелехин. Учитель начальных классов, гармонист-самоучка, он собрал возле себя талантливых людей. Был организован хор песни, который гастролировал далеко за пределами своей деревни. В 1968 году был выстроен новый типовой Дом культуры. Его директором была назначена Р. И. Кресцова. В 2017 году был создан ансамбль русской песни «Россиянки», руководитель – Е. Н. Нечаева. В 2018 году директором была назначена Л. М. Зорина.</p><p> Здесь ведут работу самодеятельный ансамбль русской песни «Наюнаяночки», танцевальный ансамбль «Сударушки», группа здоровья «Девчата». Ведут деятельность 8 клубных формирований, их посещает 71 человек. Творческие коллективы активно принимают участие в различных фестивалях конкурсах и занимают призовые места. В 2019 и 2020 годах Дом культуры получил I место за лучшее мероприятие в районе. В 2020 году ему было присвоено звание «Лучшее учреждение культуры». В 2021 году разработан новый проект – «Фестиваль водных фонариков», который планируется организовывать ежегодно. </p> <p> </p>   ', 'http://кдцву.рф', 'lubovzorina@inbox.ru', '[{"value": "78173821660", "comment": "нач. подразделения Зорина Любовь"}, {"value": "78173865837", "comment": "менеджер Жирохова Наталья"}]', '{"url": "https://all.culture.ru/uploads/d099787ef2ea02f1eb917e59a1a2198b.jpg", "title": "JVKIx7k3ST0.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"net