:"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-195507731&id=456239084&hash=9453204304f9ae4b&hd=2\" width=\"853\" height=\"480\"></iframe>"},{"hosting":"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-195507731&id=456239081&hash=48970de35ba54e97&hd=2\" width=\"853\" height=\"480\"></iframe>"}]', NULL, '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', '{"to": "22:00:00", "from": "10:00:00"}', '{"to": "18:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35774, '[{"url":"https://www.culture.ru/institutes/70422/orlovskii-klub","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/96549pl","serviceName":"Афиша7"}]', 35774, NULL, NULL, NULL, '2018-08-16 20:26:51+03', '2026-04-24 16:14:04+03', '0101000020E61000004F3BFC3559514740EFE53E390A404E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Теплогорский клуб', 'Великоустюгский район', 'Europe/Moscow', 'ул Центральная,д 7', NULL, 'обл Вологодская,р-н Великоустюгский,д Теплогорье,ул Центральная,д 7', '{"type": "Point", "coordinates": [46.679489, 60.458322]}', '<p>В Теплогорском клубе на протяжении нескольких десятков лет для взрослых и детей проводятся мероприятия различной направленности: по патриотическому воспитанию, к государственным праздникам, обучающие, развлекательного характера. Также односельчане активно развивают творческий потенциал, выступая на сцене клуба, на празднике деревни, ездят с концертными номерами на конкурсы, фестивали и в соседние поселения.</p> <p>Работают объединения по интересам для всех возрастных категорий:</p><ul><li> театральный кружок «Я – артист»;<br></li><li>вокальный ансамбль ветеранов «Вдохновение»;<br></li><li>спортивно-оздоровительный клуб «Здоровье – это я»;<br></li><li>вокальный ансамбль «Рябинушка»;<br></li><li>вокальная группа «Кураж».</li></ul>', 'http://кдцву.рф', 'teplkeltyra@yandex.ru', '[{"value": "79997919686", "comment": "Нач. подразделения Наталья Анатольевна Вологдина"}, {"value": "79814380719", "comment": "Худ. руководитель Мария Валериевна Шорохова"}]', '{"url": "https://all.culture.ru/uploads/c5d5e2e587db0c47fc1f2d519aef6169.jpg", "title": "U17J2_A-mZI.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'МБУК «Великоустюгский культурно-досуговый центр»', 'Великоустюгский район', 'Europe/Moscow', 'пр-кт Советский,д 101', NULL, 'обл Вологодская,р-н Великоустюгский,г Великий Устюг,пр-кт Советский,д 101', NULL, 3526015975, 'mincult', 'Великоустюгский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Кузинский клуб\"","networkId":"170421267","updateDate":"2023-04-05T11:45:45Z","createDate":"2023-04-05T11:45:45Z","accountId":46589,"postingGroupId":41531},{"network":"vk","name":"\"Усть-Алексеевский клуб\"","networkId":"196143083","updateDate":"2023-04-05T13:11:25Z","createDate":"2023-04-05T13:11:25Z","ac