network":"vk","name":"Парк культуры и отдыха /Великий Устюг/","networkId":"153198570","updateDate":"2023-04-05T11:46:08Z","createDate":"2023-04-05T11:46:08Z","accountId":46589,"postingGroupId":41532},{"network":"vk","name":"Полдарский клуб","networkId":"206228726","updateDate":"2023-07-05T08:23:33Z","createDate":"2023-07-05T08:23:33Z","accountId":46589,"postingGroupId":42639},{"network":"vk","name":"Театр Деда Мороза","networkId":"199304892","updateDate":"2020-11-03T05:54:59Z","createDate":"2020-11-03T05:54:59Z","accountId":21245,"postingGroupId":30273}]', 20409, '[{"id": 24, "name": "История", "sysName": "istoriya"}, {"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 28, "name": "Литература", "sysName": "literatura"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 392, "name": "Книги", "sysName": "knigi"}, {"id": 751, "name": "Культура для школьников", "sysName": "kultura-dlya-shkolnikov"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', '[{"hosting":"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-97047864&id=456239061&hash=ed29c845a0e885e8&hd=2\" width=\"853\" height=\"480\"></iframe>"},{"hosting":"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-97047864&id=456239056&hash=3d9e8bf124fcfb81&hd=2\" width=\"853\" height=\"480\"></iframe>"},{"hosting":"vk","id":"<iframe width=\"607\" height=\"360\" src=\"https://www.youtube.com/embed/AjFU-fx8htE\"></iframe>"},{"hosting":"vk","id":"<iframe src=\"https://vk.com/video_ext.php?oid=-53437447&id=456242161&hash=eea4ad7fb6b0eb28&hd=2\" width=\"853\" height=\"480\"></iframe>"}]', '{"to": "15:00:00", "from": "10:00:00"}', '{"to": "15:00:00", "from": "10:00:00"}', '{"to": "15:00:00", "from": "10:00:00"}', '{"to": "15:00:00", "from": "10:00:00"}', '{"to": "15:00:00", "from": "10:00:00"}', '{"to": "23:00:00", "from": "20:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 73510, '[{"url":"https://www.culture.ru/institutes/86614/teplogorskii-klub","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/velikiy-ustyug/dvorcy-kultury-i-kluby/96574pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=52cfae86-2798-4211-aafa-b3fabea31316&shareType=venue","serviceName":"ФанТам"}]', 73510, NULL, NULL, NULL, '2022-11-29 15:12:03+03', '2026-05-12 10:54:52+03', '0101000020E6100000F17EDC7EF9564740C784984BAA3A4E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Нюксенский центр культурного развития', 'Нюксенский район', 'Europe/Moscow', 'ул Советская,стр 14', 'строение 1', 'обл Вологодская,р-н Нюксенский,с Нюксеница,ул Советская,стр 14', '{"type": "Point", "coordinates": [44.243142, 60.409515]}', '<p>  Строительство Дома культуры в Нюксенице велось с 2019 года и было сдано в эксплуатацию в 2025 году. В этом же здании так же находится библиотека, музей и даже ЗАГС. </p><p>В настоящее время на базе учреждения работают 28 клубных формирований, количество участников – 513 человек. Три коллектива имеют звание народного: народный хор ветеранов «Вдохновение», народный танцевальный коллектив «Рябиновые бусы», народный вокальный ансамбль «Россияночка». В 2022 году студия современного и народного танца «Артданс» получила звание образцового коллектива, в студии 111 участников. </p><p>За 2024 год в Центре культурного развития проведено 420 мероприятий, количество зрителей – 33 477 человек. Это концерты, спектакли, игровые программы, вечера отдыха, дискотеки, театрализованные представления.</p> <p></p>', 'http://нюкскульт.рф/', 'nksinfo@yandex.ru', '[{"value": "78174728048", "comment": ""}, {"value": "79215361084", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/2892121c628b9ebfb7a44296aff92532.jpg", "title": "P08SfER2gp2qqKLALIs3SYBllWHJZrFFLy_GJTQ3ted7DRlNLcfpv7pDX_DqyudUj1gvcqeQ3--nUjmiQyaY30bH.jpg"}', '[{"url": "https://all.culture.ru/uploads/4d7afc6c3de335b05f42166b3bd80f44.jpg", "title": "LiWBvTO_W90.jpg"}, {"url": "https://all.culture.ru/uploads/5fc4ace4aa8d0ccf54821911651298f4.jpg", "title": "20210803_160355.jpg"}, {"url": "https://all.culture.ru/uploads/3d53d02a47da3eeded8f25f8bcd11a4f.jpg", "title": "jQ0ri3_qw0m5OrAyor_BqNZk76DWdZXlDvlb8XEdaQYe02udnj1erV37Gmdj4EaFAMGO1iNpMXz1LhcABGAp_x3U.jpg"}, {"url": "https://all.culture.ru/uploads/3c107bf2e6b58d3cf002449228c26038.jpg", "title": "drsqb2erGmM.jpg"}, {"url": "https://all.culture.ru/uploads/db22b4e81747ad944d17b9feca8032e4.jpg", "title": "0o3_4YEOQcU.jpg"}, {"url": "https://all.culture.ru/uploads/18d6af56a53a928545d2e5e7a1017615.jpg", "title": "3czMzBOrfAI.jpg"}, {"url": "https://all.culture.ru/uploads/d911b8d31e6d21bc46a298c8f52bc853.jpg", "title": "YNX-FcBO9NoYFOSpFJ3BAZhacfw83kosVB-C1I_ydt7-_hPHnRFshiFAzEbHbIqukjwqxxoDYrSacFEjRY7h1qT3.jpg"}]', NULL, 'Дворцы культуры и клубы', 'МБУК «Нюксенский районный Центр культурного развития»', 'Нюксенский район', 'Europe/Moscow', 'ул Советская,д 14', NULL, 'обл Вологодская,р-н Нюксенский,с Нюксеница,ул Советская,д 14', NULL, 3515004523, 'mincult', 'Нюксенский район', 'Europe/Moscow', '[{"network":"vk","name":"Нюксенский Центр культурного развития","networkId":"50897708","updateDate":"2025-12-25T06:44:01Z","createDate":"2025-12-25T06:44:01Z","accountId":54377,"postingGroupId":49033}]', 17261, '[{"id": 42, "name": "Культурные центры", "sysName": "kulturnye-centry"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "17:00:00", "from": "08:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 34787, '[{"url":"https://www.culture.ru/institutes/69770/nyuksenskii-centr-kulturnogo-razvitiya","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/nyuksenica/dvorcy-kultury-i-kluby/99783pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=51750f42-0523-472b-9f2a-2fc328424cdd&shareType=venue","serviceName":"ФанТам"}]', 34787, NULL, NULL, NULL, '2018-04-27 17:19:49+03', '2026-05-28 11:28:30+03', '0101000020E61000005B24ED461F1F4640581CCEFC6A344E40');
INSERT INTO culture_data.culture_palaces_clubs VALUES ('Заречный дом культуры', 'Кичменгско-Городецкий район', 'Europe/Moscow', 'ул Заречная,д 50', NULL, 'обл Вологодская,р-н Кичменгско-Городецкий,с Кичменгский Городок,ул Заречная,д 50', '{"type": "Point", "coordinates": [45.78227, 59.977256]}', '<p>Заречный дом культуры начал работу в феврале 1986 года. С 1 января 2020 года является филиалом ЦДК.<br></p><p>Заречный дом культуры является единственным учреждением культурно-досугового типа, расположенным в заречной части села Кичменгский Городок. В зоне обслуживания расположены Первомайская средняя школа и два дошкольных учреждения – детский сад комбинированного вида «Аленушка», детский сад «Солнышко». В здании ДК также размещается Заречная общедоступная библиотека.</p><p> На базе Заречного дома культуры располагается Дом военно-патриотического общественного движения «Юнармия». Дети-юнармейцы активно участвуют в патриотических акциях, в юнармейских конкурсах районного, областного и регионального масштаба.</p><p> С 2019 года Заречный дом культуры является опорным представительством по развитию добровольчества и волонтерства на территории района.</p> <p> </p>', NULL, 'kichmenzdk@mail.ru', '[{"value": "78174021739", "comment": "заведующая Копосова Татьяна Николаевна"}]', '{"url": "https://all.culture.ru/uploads/2641c348875dd430ea402796ecfd6c1c.jpg", "title": "JKpwDIcKPMY.jpg"}', NULL, NULL, 'Дворцы культуры и клубы', 'БУК «Районный дом культуры»', 'Кичменгско-Городецкий район', 'Europe/Moscow', 'ул Центральная', NULL, 'обл Вологодская,р-н Кичменгско-Городецкий,с Кичменгский Городок,ул Центральная', NULL, 3512005007, 'mincult', 'Кичменгско-Городецкий район', 'Europe/Moscow', NULL, 20268, '[{"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 34755, '[{"url":"https://www.culture.ru/institutes/35943/zarechnyi-dom-kultury","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/kichmengskiy-gorodok/dvorcy-kultury-i-kluby/19053pl","serviceName":"Афиша7"}]', 34755, NULL, NULL, NULL, '2018-04-25 14:16:14+03', '2026-06-08 16:15:25+03', '0101000020E61000002A52616C21E44640EEE87FB916FD4D40');
